__d(function(e,t,o,n,r,a,i){"use strict";Object.defineProperty(a,'__esModule',{value:!0}),Object.defineProperty(a,"EXERCISE_DB",{enumerable:!0,get:function(){return s}}),a.getDbExercise=function(e){return l.get(e)},a.findDbExerciseByName=function(e){return h.get(e.trim().toLowerCase())};const s=[{id:"3_4_Sit-Up",name:"3/4 Sit-Up",instructions:["Lie down on the floor and secure your feet. Your legs should be bent at the knees.","Place your hands behind or to the side of your head. You will begin with your back on the ground. This will be your starting position.","Flex your hips and spine to raise your torso toward your knees.","At the top of the contraction your torso should be perpendicular to the ground. Reverse the motion, going only \xbe of the way down.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"90_90_Hamstring",name:"90/90 Hamstring",instructions:["Lie on your back, with one leg extended straight out.","With the other leg, bend the hip and knee to 90 degrees. You may brace your leg with your hands if necessary. This will be your starting position.","Extend your leg straight into the air, pausing briefly at the top. Return the leg to the starting position.","Repeat for 10-20 repetitions, and then switch to the other leg."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:push","secondary:legs"]},{id:"Adductor_Groin",name:"Adductor/Groin",instructions:["Lie on your back with your feet raised towards the ceiling.","Have your partner hold your feet or ankles. Abduct your legs as far as you can. This will be your starting position.","Attempt to squeeze your legs together for 10 or more seconds, while your partner prevents you from doing so.","Now, relax the muscles in your legs as your partner pushes your feet apart, stretching as far as is comfortable for you. Be sure to let your partner know when the stretch is adequate to prevent overstretching or injury."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:static"]},{id:"Air_Bike",name:"Air Bike",instructions:["Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put your hands beside your head. Be careful however to not strain with the neck as you perform it. Now lift your shoulders into the crunch position.","Bring knees up to where they are perpendicular to the floor, with your lower legs parallel to the floor. This will be your starting position.","Now simultaneously, slowly go through a cycle pedal motion kicking forward with the right leg and bringing in the knee of the left leg. Bring your right elbow close to your left knee by crunching to the side, as you breathe out.","Go back to the initial position as you breathe in.","Crunch to the opposite side as you cycle your legs and bring closer your left elbow to your right knee and exhale.","Continue alternating in this manner until all of the recommended repetitions for each side have been completed."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"All_Fours_Quad_Stretch",name:"All Fours Quad Stretch",instructions:["Start off on your hands and knees, then lift your leg off the floor and hold the foot with your hand.","Use your hand to hold the foot or ankle, keeping the knee fully flexed, stretching the quadriceps and hip flexors.","Focus on extending your hips, thrusting them towards the floor. Hold for 10-20 seconds and then switch sides."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Alternate_Hammer_Curl",name:"Alternate Hammer Curl",instructions:["Stand up with your torso upright and a dumbbell in each hand being held at arms length. The elbows should be close to the torso.","The palms of the hands should be facing your torso. This will be your starting position.","While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.","Slowly begin to bring the dumbbells back to starting position as your breathe in.","Repeat the movement with the left hand. This equals one repetition.","Continue alternating in this manner for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Alternate_Heel_Touchers",name:"Alternate Heel Touchers",instructions:["Lie on the floor with the knees bent and the feet on the floor around 18-24 inches apart. Your arms should be extended by your side. This will be your starting position.","Crunch over your torso forward and up about 3-4 inches to the right side and touch your right heel as you hold the contraction for a second. Exhale while performing this movement.","Now go back slowly to the starting position as you inhale.","Now crunch over your torso forward and up around 3-4 inches to the left side and touch your left heel as you hold the contraction for a second. Exhale while performing this movement and then go back to the starting position as you inhale. Now that both heels have been touched, that is considered 1 repetition.","Continue alternating sides in this manner until all prescribed repetitions are done."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Alternate_Incline_Dumbbell_Curl",name:"Alternate Incline Dumbbell Curl",instructions:["Sit down on an incline bench with a dumbbell in each hand being held at arms length. Tip: Keep the elbows close to the torso.This will be your starting position.","While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. As you do so, rotate the hand so that the palm is facing up. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.","Slowly begin to bring the dumbbell back to starting position as your breathe in.","Repeat the movement with the left hand. This equals one repetition.","Continue alternating in this manner for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Alternate_Leg_Diagonal_Bound",name:"Alternate Leg Diagonal Bound",instructions:["Assume a comfortable stance with one foot slightly in front of the other.","Begin by pushing off with the front leg, driving the opposite knee forward and as high as possible before landing. Attempt to cover as much distance to each side with each bound.","It may help to use a line on the ground to guage distance from side to side.","Repeat the sequence with the other leg."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Alternating_Deltoid_Raise",name:"Alternating Deltoid Raise",instructions:["In a standing position, hold a pair of dumbbells at your side.","Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.","Return the weights to your side.","On the next repetition, raise the weights laterally, raising them out to your side to about shoulder height.","Return the weights to the starting position and continue alternating to the front and side."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Ankle_Circles",name:"Ankle Circles",instructions:["Use a sturdy object like a squat rack to hold yourself.","Lift the right leg in the air (just around 2 inches from the floor) and perform a circular motion with the big toe. Pretend that you are drawing a big circle with it. Tip: One circle equals 1 repetition. Breathe normally as you perform the movement.","When you are done with the right foot, then repeat with the left leg."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","mechanic:isolation"]},{id:"Ankle_On_The_Knee",name:"Ankle On The Knee",instructions:["From a lying position, bend your knees and keep your feet on the floor.","Place your ankle of one foot on your opposite knee.","Grasp the thigh or knee of the bottom leg and pull both of your legs into the chest. Relax your neck and shoulders. Hold for 10-20 seconds and then switch sides."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"stretching",tags:["force:static"]},{id:"Arm_Circles",name:"Arm Circles",instructions:["Stand up and extend your arms straight out by the sides. The arms should be parallel to the floor and perpendicular (90-degree angle) to your torso. This will be your starting position.","Slowly start to make circles of about 1 foot in diameter with each outstretched arm. Breathe normally as you perform the movement.","Continue the circular motion of the outstretched arms for about ten seconds. Then reverse the movement, going the opposite direction."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:push","mechanic:isolation","secondary:upper_body"]},{id:"Arnold_Dumbbell_Press",name:"Arnold Dumbbell Press",instructions:["Sit on an exercise bench with back support and hold two dumbbells in front of you at about upper chest level with your palms facing your body and your elbows bent. Tip: Your arms should be next to your torso. The starting position should look like the contracted portion of a dumbbell curl.","Now to perform the movement, raise the dumbbells as you rotate the palms of your hands until they are facing forward.","Continue lifting the dumbbells until your arms are extended above you in straight arm position. Breathe out as you perform this portion of the movement.","After a second pause at the top, begin to lower the dumbbells to the original position by rotating the palms of your hands towards you. Tip: The left arm will be rotated in a counter clockwise manner while the right one will be rotated clockwise. Breathe in as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Around_The_Worlds",name:"Around The Worlds",instructions:["Lay down on a flat bench holding a dumbbell in each hand with the palms of the hands facing towards the ceiling. Tip: Your arms should be parallel to the floor and next to your thighs. To avoid injury, make sure that you keep your elbows slightly bent. This will be your starting position.","Now move the dumbbells by creating a semi-circle as you displace them from the initial position to over the head. All of the movement should happen with the arms parallel to the floor at all times. Breathe in as you perform this portion of the movement.","Reverse the movement to return the weight to the starting position as you exhale."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Back_Flyes_-_With_Bands",name:"Back Flyes - With Bands",instructions:["Run a band around a stationary post like that of a squat rack.","Grab the band by the handles and stand back so that the tension in the band rises.","Extend and lift the arms straight in front of you. Tip: Your arms should be straight and parallel to the floor while perpendicular to your torso. Your feet should be firmly planted on the floor spread at shoulder width. This will be your starting position.","As you exhale, move your arms to the sides and back. Keep your arms extended and parallel to the floor. Continue the movement until the arms are extended to your sides.","After a pause, go back to the original position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:back_posture","secondary:arms"]},{id:"Backward_Medicine_Ball_Throw",name:"Backward Medicine Ball Throw",instructions:["This exercise is best done with a partner. If you lack a partner, the ball can be thrown and retrieved or thrown against a wall.","Begin standing a few meters in front of your partner, both facing the same direction. Begin holding the ball between your legs.","Squat down and then forcefully reverse direction, coming to full extension and you toss the ball over your head to your partner.","Your partner can then roll the ball back to you. Repeat for the desired number of repetitions."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound"]},{id:"Ball_Leg_Curl",name:"Ball Leg Curl",instructions:["Begin on the floor laying on your back with your feet on top of the ball.","Position the ball so that when your legs are extended your ankles are on top of the ball. This will be your starting position.","Raise your hips off of the ground, keeping your weight on the shoulder blades and your feet.","Flex the knees, pulling the ball as close to you as you can, contracting the hamstrings.","After a brief pause, return to the starting position."],muscleGroups:["legs"],equipment:["pilates_equipment"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:legs","secondary:glutes"]},{id:"Band_Hip_Adductions",name:"Band Hip Adductions",instructions:["Anchor a band around a solid post or other object.","Stand with your left side to the post, and put your right foot through the band, getting it around the ankle.","Stand up straight and hold onto the post if needed. This will be your starting position.","Keeping the knee straight, raise your right legs out to the side as far as you can.","Return to the starting position and repeat for the desired rep count.","Switch sides."],muscleGroups:["legs"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Band_Pull_Apart",name:"Band Pull Apart",instructions:["Begin with your arms extended straight out in front of you, holding the band with both hands.","Initiate the movement by performing a reverse fly motion, moving your hands out laterally to your sides.","Keep your elbows extended as you perform the movement, bringing the band to your chest. Ensure that you keep your shoulders back during the exercise.","Pause as you complete the movement, returning to the starting position under control."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:back_posture","secondary:upper_body"]},{id:"Band_Skull_Crusher",name:"Band Skull Crusher",instructions:["Secure a band to the base of a rack or the bench. Lay on the bench so that the band is lined up with your head.","Take hold of the band, raising your elbows so that the upper arm is perpendicular to the floor. With the elbow flexed, the band should be above your head. This will be your starting position.","Extend through the elbow to straighten your arm, keeping your upper arm in place. Pause at the top of the motion, and return to the starting position."],muscleGroups:["arms"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Bench_Dips",name:"Bench Dips",instructions:["For this exercise you will need to place a bench behind your back. With the bench perpendicular to your body, and while looking away from it, hold on to the bench on its edge with the hands fully extended, separated at shoulder width. The legs will be extended forward, bent at the waist and perpendicular to your torso. This will be your starting position.","Slowly lower your body as you inhale by bending at the elbows until you lower yourself far enough to where there is an angle slightly smaller than 90 degrees between the upper arm and the forearm. Tip: Keep the elbows as close as possible throughout the movement. Forearms should always be pointing down.","Using your triceps to bring your torso up again, lift yourself back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Bench_Jump",name:"Bench Jump",instructions:["Begin with a box or bench 1-2 feet in front of you. Stand with your feet shoulder width apart. This will be your starting position.","Perform a short squat in preparation for the jump; swing your arms behind you.","Rebound out of this position, extending through the hips, knees, and ankles to jump as high as possible. Swing your arms forward and up.","Jump over the bench, landing with the knees bent, absorbing the impact through the legs.","Turn around and face the opposite direction, then jump back over the bench."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Bench_Press_-_With_Bands",name:"Bench Press - With Bands",instructions:["Using a flat bench secure a band under the leg of the bench that is nearest to your head.","Once the band is secure, grab it by both handles and lie down on the bench.","Extend your arms so that you are holding the band handles in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","Bring down the handles slowly until your elbow forms a 90 degree angle. Keep full control at all times.","As you breathe out, bring the handles up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions of your training program."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Bent_Over_Dumbbell_Rear_Delt_Raise_With_Head_On_Bench",name:"Bent Over Dumbbell Rear Delt Raise With Head On Bench",instructions:["Stand up straight while holding a dumbbell in each hand and with an incline bench in front of you.","While keeping your back straight and maintaining the natural arch of your back, lean forward until your forehead touches the bench in front of you. Let the arms hang in front of you perpendicular to the ground. The palms of your hands should be facing each other and your torso should be parallel to the floor. This will be your starting position.","Keeping your torso forward and stationary, and the arms straight with a slight bend at the elbows, lift the dumbbells straight to the side until both arms are parallel to the floor. Exhale as you lift the weights. Caution: avoid swinging the torso or bringing the arms back as opposed to the side.","After a one second contraction at the top, slowly lower the dumbbells back to the starting position.","Repeat the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Bent_Over_Two-Dumbbell_Row",name:"Bent Over Two-Dumbbell Row",instructions:["With a dumbbell in each hand (palms facing your torso), bend your knees slightly and bring your torso forward by bending at the waist; as you bend make sure to keep your back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.","While keeping the torso stationary, lift the dumbbells to your side (as you breathe out), keeping the elbows close to the body (do not exert any force with the forearm other than holding the weights). On the top contracted position, squeeze the back muscles and hold for a second.","Slowly lower the weight again to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["back_posture"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture","secondary:upper_body"]},{id:"Bent_Over_Two-Dumbbell_Row_With_Palms_In",name:"Bent Over Two-Dumbbell Row With Palms In",instructions:["With a dumbbell in each hand (palms facing each other), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.","While keeping the torso stationary, lift the dumbbells to your side as you breathe out, squeezing your shoulder blades together. On the top contracted position, squeeze the back muscles and hold for a second.","Slowly lower the weight again to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["back_posture"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture"]},{id:"Bent-Arm_Dumbbell_Pullover",name:"Bent-Arm Dumbbell Pullover",instructions:["Place a dumbbell standing up on a flat bench.","Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.","Grasp the dumbbell with both hands and hold it straight over your chest with a bend in your arms. Both palms should be pressing against the underside one of the sides of the dumbbell. This will be your starting position. Caution: Always ensure that the dumbbell used for this exercise is secure. Using a dumbbell with loose plates can result in the dumbbell falling apart and falling on your face.","While keeping your arms locked in the bent arm position, lower the weight slowly in an arc behind your head while breathing in until you feel a stretch on the chest.","At that point, bring the dumbbell back to the starting position using the arc through which the weight was lowered and exhale as you perform this movement.","Hold the weight on the initial position for a second and repeat the motion for the prescribed number of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:back_posture","secondary:upper_body","secondary:arms"]},{id:"Bent-Knee_Hip_Raise",name:"Bent-Knee Hip Raise",instructions:["Lay flat on the floor with your arms next to your sides.","Now bend your knees at around a 75 degree angle and lift your feet off the floor by around 2 inches.","Using your lower abs, bring your knees in towards you as you maintain the 75 degree angle bend in your legs. Continue this movement until you raise your hips off of the floor by rolling your pelvis backward. Breathe out as you perform this portion of the movement. Tip: At the end of the movement your knees will be over your chest.","Squeeze your abs at the top of the movement for a second and then return to the starting position slowly as you breathe in. Tip: Maintain a controlled motion at all times.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Body_Tricep_Press",name:"Body Tricep Press",instructions:["Position a bar in a rack at chest height.","Standing, take a shoulder width grip on the bar and step a yard or two back, feet together and arms extended so that you are leaning on the bar. This will be your starting position.","Begin by flexing the elbow, lowering yourself towards the bar.","Pause, and then reverse the motion by extending the elbows.","Progress from bodyweight by adding chains over your shoulders."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Body-Up",name:"Body-Up",instructions:["Assume a plank position on the ground. You should be supporting your bodyweight on your toes and forearms, keeping your torso straight. Your forearms should be shoulder-width apart. This will be your starting position.","Pressing your palms firmly into the ground, extend through the elbows to raise your body from the ground. Keep your torso rigid as you perform the movement.","Slowly lower your forearms back to the ground by allowing the elbows to flex.","Repeat."],muscleGroups:["arms"],equipment:[],level:"intermediate",category:"strength",tags:["force:push","mechanic:isolation","secondary:core_abs","secondary:arms"]},{id:"Bodyweight_Squat",name:"Bodyweight Squat",instructions:["Stand with your feet shoulder width apart. You can place your hands behind your head. This will be your starting position.","Begin the movement by flexing your knees and hips, sitting back with your hips.","Continue down to full depth if you are able,and quickly reverse the motion until you return to the starting position. As you squat, keep your head and chest up and push your knees out."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:glutes","secondary:legs"]},{id:"Bodyweight_Walking_Lunge",name:"Bodyweight Walking Lunge",instructions:["Begin standing with your feet shoulder width apart and your hands on your hips.","Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.","Drive through the heel of your lead foot and extend both knees to raise yourself back up.","Step forward with your rear foot, repeating the lunge on the opposite leg."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Bottoms_Up",name:"Bottoms Up",instructions:["Begin by lying on your back on the ground. Your legs should be straight and your arms at your side. This will be your starting position.","To perform the movement, tuck the knees toward your chest by flexing the hips and knees. Following this, extend your legs directly above you so that they are perpendicular to the ground. Rotate and elevate your pelvis to raise your glutes from the floor.","After a brief pause, return to the starting position."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Butt_Lift_Bridge",name:"Butt Lift (Bridge)",instructions:["Lie flat on the floor on your back with the hands by your side and your knees bent. Your feet should be placed around shoulder width. This will be your starting position.","Pushing mainly with your heels, lift your hips off the floor while keeping your back straight. Breathe out as you perform this part of the motion and hold at the top for a second.","Slowly go back to the starting position as you breathe in."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation","secondary:legs"]},{id:"Butt-Ups",name:"Butt-Ups",instructions:["Begin a pushup position but with your elbows on the ground and resting on your forearms. Your arms should be bent at a 90 degree angle.","Arch your back slightly out rather than keeping your back completely straight.","Raise your glutes toward the ceiling, squeezing your abs tightly to close the distance between your ribcage and hips. The end result will be that you'll end up in a high bridge position. Exhale as you perform this portion of the movement.","Lower back down slowly to your starting position as you breathe in. Tip: Don't let your back sag downwards.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Calf_Raise_On_A_Dumbbell",name:"Calf Raise On A Dumbbell",instructions:["Hang on to a sturdy object for balance and stand on a dumbbell handle, preferably one with round plates so that it rolls as in this manner you have to work harder to stabilize yourself; thus increasing the effectiveness of the exercise.","Now roll your foot slightly forward so that you can get a nice stretch of the calf. This will be your starting position.","Lift the calf as you roll your foot over the top of the handle so that you get a full extension. Exhale during the execution of this movement. Contract the calf hard at the top and hold for a second. Tip: As you come up, roll the dumbbell slightly backward.","Now inhale as you roll the dumbbell slightly forward as you come down to get a better stretch.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Calf_Raises_-_With_Bands",name:"Calf Raises - With Bands",instructions:["Grab an exercise band and stand on it with your toes making sure that the length of the band between the foot and the arms is the same for both sides.","While holding the handles of the band, raise the arms to the side of your head as if you were getting ready to perform a shoulder press. The palms should be facing forward with the elbows bent and to the sides. This movement will create tension on the band. This will be your starting position.","Keeping the hands by your shoulder, stand up on your toes as you exhale and contract the calves hard at the top of the movement.","After a one second contraction, slowly go back down to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Calf_Stretch_Elbows_Against_Wall",name:"Calf Stretch Elbows Against Wall",instructions:["Stand facing a wall from a couple feet away.","Lean against the wall, placing your weight on your forearms.","Attempt to keep your heels on the ground. Hold for 10-20 seconds. You may move further or closer the wall, making it more or less difficult, respectively."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Calf_Stretch_Hands_Against_Wall",name:"Calf Stretch Hands Against Wall",instructions:["Stand facing a wall from several feet away. Stagger your stance, placing one foot forward.","Lean forward and rest your hands on the wall, keeping your heel, hip and head in a straight line.","Attempt to keep your heel on the ground. Hold for 10-20 seconds and then switch sides."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Carioca_Quick_Step",name:"Carioca Quick Step",instructions:["Begin with your feet a few inches apart and your left arm up in a relaxed, athletic position.","With your right foot, quick step behind and pull the knee up.","Fire your arms back up when you pull the right knee, being sure that your knee goes straight up and down. Avoid turning your feet as you move and continue to look forward as you move to the side."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["secondary:core_abs","secondary:legs","secondary:glutes"]},{id:"Cat_Stretch",name:"Cat Stretch",instructions:["Position yourself on the floor on your hands and knees.","Pull your belly in and round your spine, lower back, shoulders, and neck, letting your head drop.","Hold for 15 seconds."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:back_posture","secondary:upper_body"]},{id:"Catch_and_Overhead_Throw",name:"Catch and Overhead Throw",instructions:["Begin standing while facing a wall or a partner.","Using both hands, position the ball behind your head, stretching as much as possible, and forcefully throw the ball forward.","Ensure that you follow your throw through, being prepared to receive your rebound from your throw. If you are throwing against the wall, make sure that you stand close enough to the wall to receive the rebound, and aim a little higher than you would with a partner."],muscleGroups:["back_posture"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body"]},{id:"Chair_Lower_Back_Stretch",name:"Chair Lower Back Stretch",instructions:["Sit upright on a chair.","Bend to one side with your arm over your head. You can hold onto the chair with your free hand.","Hold for 10 seconds, and repeat for your other side."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:back_posture"]},{id:"Chest_Push_from_3_point_stance",name:"Chest Push from 3 point stance",instructions:["Begin in a three point stance, squatted down with your back flat and one hand on the ground. Place the medicine ball directly in front of you.","To begin, take your first step as you pull the ball to your chest, positioning both hands to prepare for the throw.","As you execute the second step, explosively release the ball forward as hard as possible."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Chest_Push_multiple_response",name:"Chest Push (multiple response)",instructions:["Begin in a kneeling position facing a wall or utilize a partner. Hold the ball with both hands tight into the chest.","Execute the pass by exploding forward and outward with the hips while pushing the ball as hard as possible.","Follow through by falling forward, catching yourself with your hands.","Immediately return to an upright position. Repeat for the desired number of repetitions."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Chest_Push_single_response",name:"Chest Push (single response)",instructions:["Begin in a kneeling position holding the medicine ball with both hands tightly into the chest.","Execute the pass by exploding forward and outward with the hips while pushing the ball as far as possible.","Follow through by falling forward, catching yourself with your hands."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Chest_Push_with_Run_Release",name:"Chest Push with Run Release",instructions:["Begin in an athletic stance with the knees bent, hips back, and back flat. Hold the medicine ball near your legs. This will be your starting position.","While taking your first step draw the medicine ball into your chest.","As you take the second step, explosively push the ball forward, immediately sprinting for 10 yards after the release. If you are really fast, you can catch your own pass!"],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Chest_Stretch_on_Stability_Ball",name:"Chest Stretch on Stability Ball",instructions:["Get on your hands and knees next to an exercise ball.","Place your elbows on top of the ball, keeping your arm out to your side. This will be your starting position.","Lower your torso towards the floor, keeping your elbow on top of the ball. Hold the stretch for 20-30 seconds, and repeat with the other arm."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Childs_Pose",name:"Child's Pose",instructions:["Get on your hands and knees, walk your hands in front of you.","Lower your buttocks down to sit on your heels. Let your arms drag along the floor as you sit back to stretch your entire spine.","Once you settle onto your heels, bring your hands next to your feet and relax. \"breathe\" into your back. Rest your forehead on the floor. Avoid this position if you have knee problems."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:glutes","secondary:back_posture"]},{id:"Chin_To_Chest_Stretch",name:"Chin To Chest Stretch",instructions:["Get into a seated position on the floor.","Place both hands at the rear of your head, fingers interlocked, thumbs pointing down and elbows pointing straight ahead. Slowly pull your head down to your chest. Hold for 20-30 seconds."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:upper_body"]},{id:"Chin-Up",name:"Chin-Up",instructions:["Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.","As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.","As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.","After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement.","Repeat this motion for the prescribed amount of repetitions."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture"]},{id:"Clock_Push-Up",name:"Clock Push-Up",instructions:["Move into a prone position on the floor, supporting your weight on your hands and toes.","Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.","Descend by flexing at the elbow, lowering your chest toward the ground.","At the bottom, reverse the motion by pushing yourself up through elbow extension as quickly as possible until you are air borne. Aim to \"jump\" 12-18 inches to one side.","As you accelerate up, move your outside foot away from your direction of travel. Leaving the ground, shift your body about 30 degrees for the next repetition.","Return to the starting position and repeat the exercise, working all the way around until you are back where you started."],muscleGroups:["upper_body"],equipment:[],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Close-Grip_Dumbbell_Press",name:"Close-Grip Dumbbell Press",instructions:["Place a dumbbell standing up on a flat bench.","Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench with only your shoulders lying on the surface. Hips should be below the bench and your legs bent with your feet firmly on the floor.","Grasp the dumbbell with both hands and hold it straight over your chest at arm's length. Both palms should be pressing against the underside of the sides of the dumbbell. This will be your starting position.","Initiate the movement by lowering the dumbbell to your chest.","Return to the starting position by extending the elbows."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Close-Grip_Push-Up_off_of_a_Dumbbell",name:"Close-Grip Push-Up off of a Dumbbell",instructions:["Lie on the floor and place your hands on an upright dumbbell. Supporting your weight on your toes and hands, keep your torso rigid and your elbows in with your arms straight. This will be your starting position.","Lower your body, allowing the elbows to flex while you inhale. Keep your body straight, not allowing your hips to rise or sag.","Press yourself back up to the starting position by extending the elbows. Breathe out as you perform this step.","After a pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],muscleGroups:["arms"],equipment:[],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body"]},{id:"Cocoons",name:"Cocoons",instructions:["Begin by lying on your back on the ground. Your legs should be straight and your arms extended behind your head. This will be your starting position.","To perform the movement, tuck the knees toward your chest, rotating your pelvis to lift your glutes from the floor. As you do so, flex the spine, bringing your arms back over your head to perform a simultaneous crunch motion.","After a brief pause, return to the starting position."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Concentration_Curls",name:"Concentration Curls",instructions:["Sit down on a flat bench with one dumbbell in front of you between your legs. Your legs should be spread with your knees bent and feet on the floor.","Use your right arm to pick the dumbbell up. Place the back of your right upper arm on the top of your inner right thigh. Rotate the palm of your hand until it is facing forward away from your thigh. Tip: Your arm should be extended and the dumbbell should be above the floor. This will be your starting position.","While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: At the top of the movement make sure that the little finger of your arm is higher than your thumb. This guarantees a good contraction. Hold the contracted position for a second as you squeeze the biceps.","Slowly begin to bring the dumbbells back to starting position as your breathe in. Caution: Avoid swinging motions at any time.","Repeat for the recommended amount of repetitions. Then repeat the movement with the left arm."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Cross_Body_Hammer_Curl",name:"Cross Body Hammer Curl",instructions:["Stand up straight with a dumbbell in each hand. Your hands should be down at your side with your palms facing in.","While keeping your palms facing in and without twisting your arm, curl the dumbbell of the right arm up towards your left shoulder as you exhale. Touch the top of the dumbbell to your shoulder and hold the contraction for a second.","Slowly lower the dumbbell along the same path as you inhale and then repeat the same movement for the left arm.","Continue alternating in this fashion until the recommended amount of repetitions is performed for each arm."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Cross_Over_-_With_Bands",name:"Cross Over - With Bands",instructions:["Secure an exercise band around a stationary post.","While facing away from the post, grab the handles on both ends of the band and step forward enough to create tension on the band.","Raise your arms to the sides, parallel to the floor, perpendicular to your torso (your torso and the arms should resemble the letter \"T\") and with the palms facing forward. Have them extended with a slight bend at the elbows. This will be your starting position.","While keeping your arms straight, bring them across your chest in a semicircular motion to the front as you exhale and flex your pecs. Hold the contraction for a second.","Slowly return to the starting position as you inhale.","Perform for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:arms","secondary:upper_body"]},{id:"Cross-Body_Crunch",name:"Cross-Body Crunch",instructions:["Lie flat on your back and bend your knees about 60 degrees.","Keep your feet flat on the floor and place your hands loosely behind your head. This will be your starting position.","Now curl up and bring your right elbow and shoulder across your body while bring your left knee in toward your left shoulder at the same time. Reach with your elbow and try to touch your knee. Exhale as you perform this movement. Tip: Try to bring your shoulder up towards your knee rather than just your elbow and remember that the key is to contract the abs as you perform the movement; not just to move the elbow.","Now go back down to the starting position as you inhale and repeat with the left elbow and the right knee.","Continue alternating in this manner until all prescribed repetitions are done."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Crossover_Reverse_Lunge",name:"Crossover Reverse Lunge",instructions:["Stand with your feet shoulder width apart. This will be your starting position.","Perform a rear lunge by stepping back with one foot and flexing the hips and front knee. As you do so, rotate your torso across the front leg.","After a brief pause, return to the starting position and repeat on the other side, continuing in an alternating fashion."],muscleGroups:["back_posture"],equipment:[],level:"intermediate",category:"stretching",tags:["force:pull","secondary:core_abs","secondary:legs","secondary:glutes"]},{id:"Crunch_-_Hands_Overhead",name:"Crunch - Hands Overhead",instructions:["Lie on the floor with your back flat and knees bent with around a 60-degree angle between the hamstrings and the calves.","Keep your feet flat on the floor and stretch your arms overhead with your palms crossed. This will be your starting position.","Curl your upper body forward and bring your shoulder blades just off the floor. At all times, keep your arms aligned with your head, neck and shoulder. Don't move them forward from that position. Exhale as you perform this portion of the movement and hold the contraction for a second.","Slowly lower down to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Crunch_-_Legs_On_Exercise_Ball",name:"Crunch - Legs On Exercise Ball",instructions:["Lie flat on your back with your feet resting on an exercise ball and your knees bent at a 90 degree angle.","Place your feet three to four inches apart and point your toes inward so they touch.","Place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head.","Push the small of your back down in the floor in order to better isolate your abdominal muscles. This will be your starting position.","Begin to roll your shoulders off the floor and continue to push down as hard as you can with your lower back. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. Breathe out as you execute this portion of the movement. Squeeze your abdominals hard at the top of the contraction and hold for a second. Tip: Focus on a slow, controlled movement. Refrain from using momentum at any time.","Slowly go back down to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Crunches",name:"Crunches",instructions:["Lie flat on your back with your feet flat on the ground, or resting on a bench with your knees bent at a 90 degree angle. If you are resting your feet on a bench, place them three to four inches apart and point your toes inward so they touch.","Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head.","While pushing the small of your back down in the floor to better isolate your abdominal muscles, begin to roll your shoulders off the floor.","Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don't cheat yourself by using momentum.","After the one second contraction, begin to come down slowly again to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Cuban_Press",name:"Cuban Press",instructions:["Take a dumbbell in each hand with a pronated grip in a standing position. Raise your upper arms so that they are parallel to the floor, allowing your lower arms to hang in the \"scarecrow\" position. This will be your starting position.","To initiate the movement, externally rotate the shoulders to move the upper arm 180 degrees. Keep the upper arms in place, rotating the upper arms until the wrists are directly above the elbows, the forearms perpendicular to the floor.","Now press the dumbbells by extending at the elbows, straightening your arms overhead.","Return to the starting position as you breathe in by reversing the steps.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Dancers_Stretch",name:"Dancer's Stretch",instructions:["Sit up on the floor.","Cross your right leg over your left, keeping the knee bent. Your left leg is straight and down on the floor.","Place your left arm on your right leg and your right hand on the floor.","Rotate your upper body to the right, and hold for 10-20 seconds. Switch sides."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:legs","secondary:glutes"]},{id:"Dead_Bug",name:"Dead Bug",instructions:["Begin lying on your back with your hands extended above you toward the ceiling.","Bring your feet, knees, and hips up to 90 degrees.","Exhale hard to bring your ribcage down and flatten your back onto the floor, rotating your pelvis up and squeezing your glutes. Hold this position throughout the movement. This will be your starting position.","Initiate the exercise by extending one leg, straightening the knee and hip to bring the leg just above the ground.","Maintain the position of your lumbar and pelvis as you perform the movement, as your back is going to want to arch.","Stay tight and return the working leg to the starting position.","Repeat on the opposite side, alternating until the set is complete."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Decline_Crunch",name:"Decline Crunch",instructions:["Secure your legs at the end of the decline bench and lie down.","Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head.","While pushing the small of your back down in the bench to better isolate your abdominal muscles, begin to roll your shoulders off it.","Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the bench only about four inches, and your lower back should remain on the bench. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don't cheat yourself by using momentum.","After the one second contraction, begin to come down slowly again to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Decline_Dumbbell_Bench_Press",name:"Decline Dumbbell Bench Press",instructions:["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","Once you are laying down, move the dumbbells in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","Bring down the weights slowly to your side as you breathe out. Keep full control of the dumbbells at all times. Tip: Throughout the motion, the forearms should always be perpendicular to the floor.","As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up..","Repeat the movement for the prescribed amount of repetitions of your training program."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Decline_Dumbbell_Flyes",name:"Decline Dumbbell Flyes",instructions:["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.","With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.","Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.","Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound"]},{id:"Decline_Dumbbell_Triceps_Extension",name:"Decline Dumbbell Triceps Extension",instructions:["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.","As you breathe in and you keep the upper arms stationary (and elbows in), bring the dumbbells down slowly by moving your forearms in a semicircular motion towards you until your thumbs are next to your ears. Breathe in as you perform this portion of the movement.","Lift the dumbbells back to the starting position by contracting the triceps and exhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Decline_Oblique_Crunch",name:"Decline Oblique Crunch",instructions:["Secure your legs at the end of the decline bench and slowly lay down on the bench.","Raise your upper body off the bench until your torso is about 35-45 degrees if measured from the floor.","Put one hand beside your head and the other on your thigh. This will be your starting position.","Raise your upper body slowly from the starting position while turning your torso to the left. Continue crunching up as you exhale until your right elbow touches your left knee. Hold this contracted position for a second. Tip: Focus on keeping your abs tight and keeping the movement slow and controlled.","Lower your body back down slowly to the starting position as you inhale.","After completing one set on the right for the recommended amount of repetitions, switch to your left side. Tip: Focus on really twisting your torso and feeling the contraction when you are in the up position."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Decline_Push-Up",name:"Decline Push-Up",instructions:["Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length. Move your feet up to a box or bench. This will be your starting position.","Next, lower yourself downward until your chest almost touches the floor as you inhale.","Now breathe out and press your upper body back up to the starting position while squeezing your chest.","After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Decline_Reverse_Crunch",name:"Decline Reverse Crunch",instructions:["Lie on your back on a decline bench and hold on to the top of the bench with both hands. Don't let your body slip down from this position.","Hold your legs parallel to the floor using your abs to hold them there while keeping your knees and feet together. Tip: Your legs should be fully extended with a slight bend on the knee. This will be your starting position.","While exhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the bench. At the end of this movement your knees will be touching your chest.","Hold the contraction for a second and move your legs back to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Dips_-_Triceps_Version",name:"Dips - Triceps Version",instructions:["To get into the starting position, hold your body at arm's length with your arms nearly locked above the bars.","Now, inhale and slowly lower yourself downward. Your torso should remain upright and your elbows should stay close to your body. This helps to better focus on tricep involvement. Lower yourself until there is a 90 degree angle formed between the upper arm and forearm.","Then, exhale and push your torso back up using your triceps to bring your body back to the starting position.","Repeat the movement for the prescribed amount of repetitions."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Double_Leg_Butt_Kick",name:"Double Leg Butt Kick",instructions:["Begin standing with your knees slightly bent.","Quickly squat a short distance, flexing the hips and knees, and immediately extend to jump for maximum vertical height.","As you go up, tuck your heels by flexing the knees, attempting to touch the buttocks.","Finish the motion by landing with the knees only partially bent, using your legs to absorb the impact."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Downward_Facing_Balance",name:"Downward Facing Balance",instructions:["Lie facedown on top of an exercise ball.","While resting on your stomach on the ball, walk your hands forward along the floor and lift your legs, extending your elbows and knees."],muscleGroups:["glutes"],equipment:["pilates_equipment"],level:"intermediate",category:"strength",tags:["force:static","mechanic:isolation","secondary:core_abs","secondary:legs"]},{id:"Dumbbell_Alternate_Bicep_Curl",name:"Dumbbell Alternate Bicep Curl",instructions:["Stand (torso upright) with a dumbbell in each hand held at arms length. The elbows should be close to the torso and the palms of your hand should be facing your thighs.","While holding the upper arm stationary, curl the right weight as you rotate the palm of the hands until they are facing forward. At this point continue contracting the biceps as you breathe out until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.","Slowly begin to bring the dumbbell back to the starting position as your breathe in. Tip: Remember to twist the palms back to the starting position (facing your thighs) as you come down.","Repeat the movement with the left hand. This equals one repetition.","Continue alternating in this manner for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Dumbbell_Bench_Press",name:"Dumbbell Bench Press",instructions:["Lie down on a flat bench with a dumbbell in each hand resting on top of your thighs. The palms of your hands will be facing each other.","Then, using your thighs to help raise the dumbbells up, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. The dumbbells should be just to the sides of your chest, with your upper arm and forearm creating a 90 degree angle. Be sure to maintain full control of the dumbbells at all times. This will be your starting position.","Then, as you breathe out, use your chest to push the dumbbells up. Lock your arms at the top of the lift and squeeze your chest, hold for a second and then begin coming down slowly. Tip: Ideally, lowering the weight should take about twice as long as raising it.","Repeat the movement for the prescribed amount of repetitions of your training program."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Dumbbell_Bench_Press_with_Neutral_Grip",name:"Dumbbell Bench Press with Neutral Grip",instructions:["Take a dumbbell in each hand and lay back onto a flat bench. Your feet should be flat on the floor and your shoulder blades retracted.","Maintaining a neutral grip, palms facing each other, begin with your arms extended directly above you, perpendicular to the floor. This will be your starting position.","Begin the movement by flexing the elbow, lowering the upper arms to the side. Descend until the dumbbells are to your torso.","Pause, then extend the elbow and return to the starting position."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Dumbbell_Bicep_Curl",name:"Dumbbell Bicep Curl",instructions:["Stand up straight with a dumbbell in each hand at arm's length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Dumbbell_Clean",name:"Dumbbell Clean",instructions:["Begin standing with a dumbbell in each hand with your feet shoulder width apart.","Lower the weights to the floor by flexing at the hips and knees, pushing your hips back until the dumbbells reach the floor. This will be your starting position.","To initiate the movement, violently jump upward by extending the hips, knees, and ankles to acclerate the weights upward. Maintaining a neutral grip on the dumbbells, keep the arms straight until full extension is reached.","After full extension, rebend the hips and knees to receive the weight in a squat position. Allow the arms to bend, guiding the dumbbells to your shoulders.","Upon receiving the weight in the squat position, extend the hips and knees to finish in a standing position with the weights on your shoulders."],muscleGroups:["legs"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:legs","secondary:arms","secondary:glutes","secondary:back_posture","secondary:upper_body"]},{id:"Dumbbell_Flyes",name:"Dumbbell Flyes",instructions:["Lie down on a flat bench with a dumbbell on each hand resting on top of your thighs. The palms of your hand will be facing each other.","Then using your thighs to help raise the dumbbells, lift the dumbbells one at a time so you can hold them in front of you at shoulder width with the palms of your hands facing each other. Raise the dumbbells up like you're pressing them, but stop and hold just before you lock out. This will be your starting position.","With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.","Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.","Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Dumbbell_Incline_Row",name:"Dumbbell Incline Row",instructions:["Using a neutral grip, lean into an incline bench.","Take a dumbbell in each hand with a neutral grip, beginning with the arms straight. This will be your starting position.","Retract the shoulder blades and flex the elbows to row the dumbbells to your side.","Pause at the top of the motion, and then return to the starting position."],muscleGroups:["back_posture"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture","secondary:upper_body"]},{id:"Dumbbell_Incline_Shoulder_Raise",name:"Dumbbell Incline Shoulder Raise",instructions:["Sit on an Incline Bench while holding a dumbbell on each hand on top of your thighs.","Lift your legs up to kick the weights to your shoulders and lean back. Position the dumbbells above your shoulders with your arms extended. The arms should be perpendicular to the floor with your palms facing forward and knuckles pointing towards the ceiling. This will be your starting position.","While keeping the arms straight and locked, lift the dumbbells by raising the shoulders from the bench as you breathe out.","Bring back the dumbbells to the starting position as you breathe in.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation","secondary:arms"]},{id:"Dumbbell_Lunges",name:"Dumbbell Lunges",instructions:["Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.","Step forward with your right leg around 2 feet or so from the foot being left stationary behind and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Note: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground.","Using mainly the heel of your foot, push up and go back to the starting position as you exhale.","Repeat the movement for the recommended amount of repetitions and then perform with the left leg."],muscleGroups:["legs"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Dumbbell_Lying_One-Arm_Rear_Lateral_Raise",name:"Dumbbell Lying One-Arm Rear Lateral Raise",instructions:["While holding a dumbbell in one hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench. The other hand can be used to hold to the leg of the bench for stability.","Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.","Now raise the arm with the dumbbell to the side until your elbow is at shoulder height and your arm is roughly parallel to the floor as you exhale. Tip: Maintain your arm perpendicular to the torso while keeping your arm extended throughout the movement. Also, keep the contraction at the top for a second.","Slowly lower the dumbbell to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation","secondary:back_posture"]},{id:"Dumbbell_Lying_Pronation",name:"Dumbbell Lying Pronation",instructions:["Lie on a flat bench face down with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.","Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.","Now raise the upper arm so that the forearm is perpendicular to the floor and the upper arm is perpendicular to your torso. Tip: The upper arm should be parallel to the floor and also creating a 90-degree angle with your torso. This will be your starting position.","As you breathe out, externally rotate your forearm so that the dumbbell is lifted forward as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is parallel to the floor. At this point you will hold the contraction for a second.","As you breathe in, slowly go back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Dumbbell_Lying_Rear_Lateral_Raise",name:"Dumbbell Lying Rear Lateral Raise",instructions:["While holding a dumbbell in each hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench.","Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.","Now raise the arms to the side until your elbows are at shoulder height and your arms are roughly parallel to the floor as you exhale. Tip: Maintain your arms perpendicular to the torso while keeping them extended throughout the movement. Also, keep the contraction at the top for a second.","Slowly lower the dumbbells to the starting position as you inhale.","Repeat for the recommended amount of repetitions and then switch to the other arm."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Dumbbell_Lying_Supination",name:"Dumbbell Lying Supination",instructions:["Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.","Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.","Now raise the upper arm so that the forearm is parallel to the floor and perpendicular to your torso (Tip: So the forearm will be directly in front of you). The upper arm will be stationary by your torso and should be parallel to the floor (aligned with your torso at all times). This will be your starting position.","As you breathe out, externally rotate your forearm so that the dumbbell is lifted up in a semicircle motion as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is perpendicular to the floor and the torso pointing towards the ceiling. At this point you will hold the contraction for a second.","As you breathe in, slowly go back to the starting position.","Repeat for the recommended amount of repetitions and then switch to the other arm."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Dumbbell_One-Arm_Shoulder_Press",name:"Dumbbell One-Arm Shoulder Press",instructions:["Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.","Clean the dumbbell up to bring it to shoulder height. The other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface.","Rotate the wrist so that the palm of your hand is facing forward. This is your starting position.","As you exhale, push the dumbbell up until your arm is fully extended.","After a second pause, slowly come down back to the starting position as you inhale.","Repeat for the recommended amount of repetitions and then switch arms."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Dumbbell_One-Arm_Triceps_Extension",name:"Dumbbell One-Arm Triceps Extension",instructions:["Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.","Clean the dumbbell up to bring it to shoulder height and then extend the arm over your head so that the whole arm is perpendicular to the floor and next to your head. The dumbbell should be on top of you. The other hand can be kept fully extended to the side, by the waist, supporting the upper arm that has the dumbbell or grabbing a fixed surface.","Rotate the wrist so that the palm of your hand is facing forward and the pinkie is facing the ceiling. This will be your starting position.","Slowly lower the dumbbell behind your head as you hold the upper arm stationary. Inhale as you perform this movement and pause when your triceps are fully stretched.","Return to the starting position by flexing your triceps as you breathe out. Tip: It is imperative that only the forearm moves. The upper arm should remain at all times stationary next to your head.","Repeat for the recommended amount of repetitions and switch arms."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Dumbbell_One-Arm_Upright_Row",name:"Dumbbell One-Arm Upright Row",instructions:["Grab a dumbbell and stand up straight with your arm extended in front of you with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be resting on top of your thigh with the palm of your hands facing your thighs.","Keep the other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface. This will be your starting position.","Use your side shoulders to lift the dumbbell as you exhale. The dumbbell should be close to the body as you move it up. Continue to lift it until the dumbbell is nearly in line with your chin. Tip: Your elbows should drive the motion. As you lift the dumbbell, your elbow should always be higher than your forearm. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the dumbbell back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions and switch arms."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:upper_body"]},{id:"Dumbbell_Prone_Incline_Curl",name:"Dumbbell Prone Incline Curl",instructions:["Grab a dumbbell on each hand and lie face down on an incline bench with your shoulders near top of the incline. Your knees can rest on the seat or your legs can be straddled to the sides (my preferred way).","Let your arms extend and hang naturally in front of you so that they are perpendicular to the floor.","Now keep your elbows in by your side and face the palms forward. This will be your starting position.","Raise the dumbbells by contracting the biceps until your arms are fully flexed. Exhale as you perform this portion of the movement and ensure that only the forearms move. The upper arms should remain stationary at all times.","Lower the dumbbells until your arms are fully extended.","Repeat for the recommended amount of times."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Dumbbell_Raise",name:"Dumbbell Raise",instructions:["Grab a dumbbell in each arm and stand up straight with your arms extended by your sides with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be next to your thighs with the palm of your hands facing back.","Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be to the side of the body as you move them up. Continue to lift it until the dumbbells are nearly in line with your chin. Tip: Your elbows should drive the motion. As you lift the dumbbell, your elbow should always be higher than your forearm. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the dumbbells back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms"]},{id:"Dumbbell_Rear_Lunge",name:"Dumbbell Rear Lunge",instructions:["Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.","Step backward with your right leg around two feet or so from the left foot and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Tip: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground. Keep the torso upright during the lunge; flexible hip flexors are important. A long lunge emphasizes the Gluteus Maximus; a short lunge emphasizes Quadriceps.","Push up and go back to the starting position as you exhale. Tip: Use the ball of your feet to push in order to accentuate the quadriceps. To focus on the glutes, press with your heels.","Now repeat with the opposite leg."],muscleGroups:["legs"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Dumbbell_Scaption",name:"Dumbbell Scaption",instructions:["This corrective exercise strengthens the muscles that stabilize your shoulder blade. Hold a light weight in each hand, hanging at your sides. Your thumbs should pointing up.","Begin the movement raising your arms out in front of you, about 30 degrees off center. Your arms should be fully extended as you perform the movement.","Continue until your arms are parallel to the ground, and then return to the starting position."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation","secondary:upper_body"]},{id:"Dumbbell_Seated_Box_Jump",name:"Dumbbell Seated Box Jump",instructions:["Position a box a couple feet to the side of a bench. Hold a dumbbell to your chest with both hands and seat yourself on the bench facing the box. This will be your starting position.","Plant your feet firmly on the ground as you lean forward, extending through the hips and knees to jump up and forward.","Land on the box with both feet, absorbing the impact by allowing the hips and knees to bend.","Step down and return to the starting position."],muscleGroups:["legs"],equipment:["dumbbells"],level:"intermediate",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Dumbbell_Seated_One-Leg_Calf_Raise",name:"Dumbbell Seated One-Leg Calf Raise",instructions:["Place a block on the floor about 12 inches from a flat bench.","Sit on a flat bench and place a dumbbell on your upper left thigh about 3 inches above your knee.","Now place the ball of your left foot on the block. This will be your starting position.","Raise your toes up as high as possible as you exhale and you contract your calf muscle. Hold the contraction for a second.","Slowly return to the starting position, stretching as far down as possible.","Repeat for your prescribed number of repetitions and then repeat with the right leg."],muscleGroups:["legs"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Dumbbell_Shoulder_Press",name:"Dumbbell Shoulder Press",instructions:["While holding a dumbbell in each hand, sit on a military press bench or utility bench that has back support. Place the dumbbells upright on top of your thighs.","Now raise the dumbbells to shoulder height one at a time using your thighs to help propel them up into position.","Make sure to rotate your wrists so that the palms of your hands are facing forward. This is your starting position.","Now, exhale and push the dumbbells upward until they touch at the top.","Then, after a brief pause at the top contracted position, slowly lower the weights back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Dumbbell_Shrug",name:"Dumbbell Shrug",instructions:["Stand erect with a dumbbell on each hand (palms facing your torso), arms extended on the sides.","Lift the dumbbells by elevating the shoulders as high as possible while you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the dumbbells. Only the shoulders should be moving up and down.","Lower the dumbbells back to the original position.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Dumbbell_Side_Bend",name:"Dumbbell Side Bend",instructions:["Stand up straight while holding a dumbbell on the left hand (palms facing the torso) as you have the right hand holding your waist. Your feet should be placed at shoulder width. This will be your starting position.","While keeping your back straight and your head up, bend only at the waist to the right as far as possible. Breathe in as you bend to the side. Then hold for a second and come back up to the starting position as you exhale. Tip: Keep the rest of the body stationary.","Now repeat the movement but bending to the left instead. Hold for a second and come back to the starting position.","Repeat for the recommended amount of repetitions and then change hands."],muscleGroups:["core_abs"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Dumbbell_Squat",name:"Dumbbell Squat",instructions:["Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).","Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.","Begin to slowly lower your torso by bending the knees as you maintain a straight posture with the head up. Continue down until your thighs are parallel to the floor. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.","Begin to raise your torso as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes","secondary:back_posture"]},{id:"Dumbbell_Squat_To_A_Bench",name:"Dumbbell Squat To A Bench",instructions:["Stand up straight with a flat bench behind you while holding a dumbbell on each hand (palms facing the side of your legs).","Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.","Begin to slowly lower your torso by bending the knees as you maintain a straight posture with the head up. Continue down until you slightly touch the bench behind you. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.","Begin to raise the bar as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes","secondary:back_posture"]},{id:"Dumbbell_Step_Ups",name:"Dumbbell Step Ups",instructions:["Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).","Place the right foot on the elevated platform. Step on the platform by extending the hip and the knee of your right leg. Use the heel mainly to lift the rest of your body up and place the foot of the left leg on the platform as well. Breathe out as you execute the force required to come up.","Step down with the left leg by flexing the hip and knee of the right leg as you inhale. Return to the original standing position by placing the right foot of to next to the left foot on the initial position.","Repeat with the right leg for the recommended amount of repetitions and then perform with the left leg."],muscleGroups:["legs"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Dumbbell_Tricep_Extension_-Pronated_Grip",name:"Dumbbell Tricep Extension -Pronated Grip",instructions:["Lie down on a flat bench holding two dumbbells directly above your shoulders. Your arms should be fully extended and form a 90 degree angle from your torso and the floor.","The palms of your hands should be facing forward, and your elbows should be tucked in. This will be your starting position.","Now, inhale and slowly lower the dumbbells until they are near your ears. Be sure to keep your upper arms stationary and your elbows tucked in.","Then, exhale and use your triceps to return the weight to the starting position."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Dynamic_Back_Stretch",name:"Dynamic Back Stretch",instructions:["Stand with your feet shoulder width apart. This will be your starting position.","Keeping your arms straight, swing them straight up in front of you 5-10 times, increasing the range of motion each time until your arms are above your head."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull"]},{id:"Dynamic_Chest_Stretch",name:"Dynamic Chest Stretch",instructions:["Stand with your hands together, arms extended directly in front of you. This will be your starting position.","Keeping your arms straight, quickly move your arms back as far as possible and back in again, similar to an exaggerated clapping motion. Repeat 5-10 times, increasing speed as you do so."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","secondary:back_posture"]},{id:"Elbow_Circles",name:"Elbow Circles",instructions:["Sit or stand with your feet slightly apart.","Place your hands on your shoulders with your elbows at shoulder level and pointing out.","Slowly make a circle with your elbows. Breathe out as you start the circle and breathe in as you complete the circle."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","mechanic:isolation","secondary:upper_body"]},{id:"Elbow_to_Knee",name:"Elbow to Knee",instructions:["Lie on the floor, crossing your right leg across your bent left knee. Clasp your hands behind your head, beginning with your shoulder blades on the ground. This will be your starting position.","Perform the motion by flexing the spine and rotating your torso to bring the left elbow to the right knee.","Return to the starting position and repeat the movement for the desired number of repetitions before switching sides."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Elbows_Back",name:"Elbows Back",instructions:["Stand up straight.","Place both hands on your lower back, fingers pointing downward and elbows out.","Then gently pull your elbows back aiming to touch them together."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:upper_body"]},{id:"Exercise_Ball_Crunch",name:"Exercise Ball Crunch",instructions:["Lie on an exercise ball with your lower back curvature pressed against the spherical surface of the ball. Your feet should be bent at the knee and pressed firmly against the floor. The upper torso should be hanging off the top of the ball. The arms should either be kept alongside the body or crossed on top of your chest as these positions avoid neck strains (as opposed to the hands behind the back of the head position).","Lower your torso into a stretch position keeping the neck stationary at all times. This will be your starting position.","With the hips stationary, flex the waist by contracting the abdominals and curl the shoulders and trunk upward until you feel a nice contraction on your abdominals. The arms should simply slide up the side of your legs if you have them at the side or just stay on top of your chest if you have them crossed. The lower back should always stay in contact with the ball. Exhale as you perform this movement and hold the contraction for a second.","As you inhale, go back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Exercise_Ball_Pull-In",name:"Exercise Ball Pull-In",instructions:["Place an exercise ball nearby and lay on the floor in front of it with your hands on the floor shoulder width apart in a push-up position.","Now place your lower shins on top of an exercise ball. Tip: At this point your legs should be fully extended with the shins on top of the ball and the upper body should be in a push-up type of position being supported by your two extended arms in front of you. This will be your starting position.","While keeping your back completely straight and the upper body stationary, pull your knees in towards your chest as you exhale, allowing the ball to roll forward under your ankles. Squeeze your abs and hold that position for a second.","Now slowly straighten your legs, rolling the ball back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"External_Rotation",name:"External Rotation",instructions:["Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.","Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm. Tip: Keep the arm parallel to your torso.","Now bend the elbow while keeping the upper arm stationary. In this manner, the forearm will be parallel to the floor and perpendicular to your torso (Tip: So the forearm will be directly in front of you). The upper arm will be stationary by your torso and should be parallel to the floor (aligned with your torso at all times). This will be your starting position.","As you breathe out, externally rotate your forearm so that the dumbbell is lifted up in a semicircle motion as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is perpendicular to the floor and the torso pointing towards the ceiling. At this point you will hold the contraction for a second.","As you breathe in, slowly go back to the starting position.","Repeat for the recommended amount of repetitions and then switch to the other arm."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"External_Rotation_with_Band",name:"External Rotation with Band",instructions:["Choke the band around a post. The band should be at the same height as your elbow. Stand with your left side to the band a couple of feet away.","Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.","With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching across the front of your torso. This will be your starting position.","Execute the movement by rotating your arm in a backhand motion, keeping your elbow in place.","Continue as far as you are able, pause, and then return to the starting position."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Fast_Skipping",name:"Fast Skipping",instructions:["Start in a relaxed position with one leg slightly forward. This will be your starting position.","Skip by executing a step-hop pattern of right-right-step to left-left-step, and so on, alternating back and forth.","Perform fast skips by maintaining close contact with the ground and reduce air time, moving as quickly as possible."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Flat_Bench_Leg_Pull-In",name:"Flat Bench Leg Pull-In",instructions:["Lie on an exercise mat or a flat bench with your legs off the end.","Place your hands either under your glutes with your palms down or by the sides holding on to the bench (or with palms down by the side on an exercise mat). Also extend your legs straight out. This will be your starting position.","Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue this movement until your knees are near your chest. Hold the contracted position for a second.","As you breathe in, slowly return to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Flat_Bench_Lying_Leg_Raise",name:"Flat Bench Lying Leg Raise",instructions:["Lie with your back flat on a bench and your legs extended in front of you off the end.","Place your hands either under your glutes with your palms down or by the sides holding on to the bench. This will be your starting position.","As you keep your legs extended, straight as possible with your knees slightly bent but locked raise your legs until they make a 90-degree angle with the floor. Exhale as you perform this portion of the movement and hold the contraction at the top for a second.","Now, as you inhale, slowly lower your legs back down to the starting position."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Flexor_Incline_Dumbbell_Curls",name:"Flexor Incline Dumbbell Curls",instructions:["Hold the dumbbell towards the side farther from you so that you have more weight on the side closest to you. (This can be done for a good effect on all bicep dumbbell exercises). Now do a normal incline dumbbell curl, but keep your wrists as far back as possible so as to neutralize any stress that is placed on them.","Sit on an incline bench that is angled at 45-degrees while holding a dumbbell on each hand.","Let your arms hang down on your sides, with the elbows in, and turn the palms of your hands forward with the thumbs pointing away from the body. Tip: You will keep this hand position throughout the movement as there should not be any twisting of the hands as they come up. This will be your starting position.","Curl up the two dumbbells at the same time until your biceps are fully contracted and exhale. Tip: Do not swing the arms or use momentum. Keep a controlled motion at all times. Hold the contracted position for a second at the top.","As you inhale, slowly go back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Floor_Glute-Ham_Raise",name:"Floor Glute-Ham Raise",instructions:["You can use a partner for this exercise or brace your feet under something stable.","Begin on your knees with your upper legs and torso upright. If using a partner, they will firmly hold your feet to keep you in position. This will be your starting position.","Lower yourself by extending at the knee, taking care to NOT flex the hips as you go forward.","Place your hands in front of you as you reach the floor. This movement is very difficult and you may be unable to do it unaided. Use your arms to lightly push off the floor to aid your return to the starting position."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation","secondary:legs","secondary:glutes"]},{id:"Flutter_Kicks",name:"Flutter Kicks",instructions:["On a flat bench lie facedown with the hips on the edge of the bench, the legs straight with toes high off the floor and with the arms on top of the bench holding on to the front edge.","Squeeze your glutes and hamstrings and straighten the legs until they are level with the hips. This will be your starting position.","Start the movement by lifting the left leg higher than the right leg.","Then lower the left leg as you lift the right leg.","Continue alternating in this manner (as though you are doing a flutter kick in water) until you have done the recommended amount of repetitions for each leg. Make sure that you keep a controlled movement at all times. Tip: You will breathe normally as you perform this movement."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:legs"]},{id:"FP_Bicycle_Crunch",name:"Bicycle Crunch",instructions:["Lie on your back with hands lightly supporting your head and legs at tabletop.","Curl up and rotate one elbow toward the opposite knee while extending the other leg long.","Switch sides in a slow, controlled pedaling motion.","Keep your lower back pressed toward the floor throughout."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["first-party"]},{id:"FP_March_In_Place",name:"March in Place",instructions:["Stand tall with your feet hip-width apart and arms relaxed at your sides.","Lift one knee toward hip height while swinging the opposite arm forward.","Lower it with control and immediately lift the other knee, settling into a steady marching rhythm.","Keep your shoulders relaxed and breathe evenly throughout."],muscleGroups:["legs","core_abs"],equipment:[],level:"beginner",category:"cardio",tags:["first-party"]},{id:"FP_Side_Steps",name:"Side Steps",instructions:["Stand with feet together and knees slightly bent.","Step wide to one side, then bring the trailing foot in to meet it.","Repeat in the other direction, keeping the steps light and springy without leaving the floor.","Add an arm reach on each step for extra rhythm."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"cardio",tags:["first-party"]},{id:"FP_Standing_Core_Twist",name:"Standing Core Twists",instructions:["Stand with feet shoulder-width apart and arms bent in front of your chest.","Rotate your torso to one side, letting the back heel pivot slightly.","Return through center and rotate to the other side in a smooth, continuous rhythm.","Keep your hips steady and let the waist do the work."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"cardio",tags:["first-party"]},{id:"FP_Standing_Knee_Drive",name:"Standing Knee Drive",instructions:["Stand tall and reach both arms overhead.","Drive one knee up toward your hands as they sweep down to meet it.","Return to standing tall and repeat on the other side, alternating with a steady rhythm.","Brace your core each time the knee lifts."],muscleGroups:["core_abs","legs"],equipment:[],level:"beginner",category:"cardio",tags:["first-party"]},{id:"FP_Standing_Punches",name:"Standing Punches",instructions:["Stand with feet staggered, knees soft, and fists guarding your chin.","Punch one arm across your body with control, rotating slightly through the torso.","Pull it back quickly and punch with the other arm, exhaling sharply with each punch.","Keep the pace brisk but the shoulders relaxed."],muscleGroups:["arms","upper_body","core_abs"],equipment:[],level:"beginner",category:"cardio",tags:["first-party"]},{id:"Freehand_Jump_Squat",name:"Freehand Jump Squat",instructions:["Cross your arms over your chest.","With your head up and your back straight, position your feet at shoulder width.","Keeping your back straight and chest up, squat down as you inhale until your upper thighs are parallel, or lower, to the floor.","Now pressing mainly with the ball of your feet, jump straight up in the air as high as possible, using the thighs like springs. Exhale during this portion of the movement.","When you touch the floor again, immediately squat down and jump again.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Frog_Hops",name:"Frog Hops",instructions:["Stand with your hands behind your head, and squat down keeping your torso upright and your head up. This will be your starting position.","Jump forward several feet, avoiding jumping unnecessarily high. As your feet contact the ground, absorb the impact through your legs, and jump again. Repeat this action 5-10 times."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Frog_Sit-Ups",name:"Frog Sit-Ups",instructions:["Lie with your back flat on the floor (or exercise mat) and your legs extended in front of you.","Now bend at the knees and place your outer thighs by the floor (or mat) as you make the soles of your feet touch each other.","Now try pushing both soles and bringing them up as near you as possible while you keep the outer thighs on the floor (or at least almost touching it). Tip: In this position your legs should create a diamond shape.","Now, cross your arms in front of you by touching the opposite shoulders. This will be your starting position.","As you exhale flatten your lower back to the floor while curling the torso upwards. Tip: This will be like performing the first 1/4 movement of a sit up. Hold at the top position for a second.","As you inhale, slowly lower back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Front_Dumbbell_Raise",name:"Front Dumbbell Raise",instructions:["Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.","While maintaining the torso stationary (no swinging), lift the left dumbbell to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top. Inhale after the second pause.","Now lower the dumbbell back down slowly to the starting position as you simultaneously lift the right dumbbell.","Continue alternating in this fashion until all of the recommended amount of repetitions have been performed for each arm."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Front_Incline_Dumbbell_Raise",name:"Front Incline Dumbbell Raise",instructions:["Sit down on an incline bench with the incline set anywhere between 30 to 60 degrees while holding a dumbbell on each hand. Tip: You can change the angle to hit the muscle a little differently each time.","Extend your arms straight in front of you and have your palms facing down with the dumbbells raised about 1 inch above your thighs. This will be your starting position.","Slowly raise the dumbbells straight up until they are slightly above your shoulders, while keeping your elbows locked. Squeeze at the top for a second and make sure you breathe out during this portion of the movement. Tip: Keep your head resting down against the bench and your legs on the floor at all times.","Lower the arms back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Front_Leg_Raises",name:"Front Leg Raises",instructions:["Stand next to a chair or other support, holding on with one hand.","Swing your leg forward, keeping the leg straight. Continue with a downward swing, bringing the leg as far back as your flexibility allows. Repeat 5-10 times, and then switch legs."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull"]},{id:"Front_Two-Dumbbell_Raise",name:"Front Two-Dumbbell Raise",instructions:["Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.","While maintaining the torso stationary (no swinging), lift the dumbbells to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arms are slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top.","As you inhale, lower the dumbbells back down slowly to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Glute_Kickback",name:"Glute Kickback",instructions:["Kneel on the floor or an exercise mat and bend at the waist with your arms extended in front of you (perpendicular to the torso) in order to get into a kneeling push-up position but with the arms spaced at shoulder width. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.","As you exhale, lift up your right leg until the hamstrings are in line with the back while maintaining the 90-degree angle bend. Contract the glutes throughout this movement and hold the contraction at the top for a second. Tip: At the end of the movement the upper leg should be parallel to the floor while the calf should be perpendicular to it.","Go back to the initial position as you inhale and now repeat with the left leg.","Continue to alternate legs until all of the recommended repetitions have been performed."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:legs"]},{id:"Gorilla_Chin_Crunch",name:"Gorilla Chin/Crunch",instructions:["Hang from a chin-up bar using an underhand grip (palms facing you) that is slightly wider than shoulder width.","Now bend your knees at a 90 degree angle so that the calves are parallel to the floor while the thighs remain perpendicular to it. This will be your starting position.","As you exhale, pull yourself up while crunching your knees up at the same time until your knees are at chest level. You will stop going up as soon as your nose is at the same level as the bar. Tip: When you get to this point you should also be finishing the crunch at the same time.","Slowly start to inhale as you return to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture"]},{id:"Groin_and_Back_Stretch",name:"Groin and Back Stretch",instructions:["Sit on the floor with your knees bent and feet together.","Interlock your fingers behind your head. This will be your starting position.","Curl downwards, bringing your elbows to the inside of your thighs. After a brief pause, return to the starting position with your head up and your back straight. Repeat for 10-20 repetitions."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:static","mechanic:compound"]},{id:"Groiners",name:"Groiners",instructions:["Begin in a pushup position on the floor. This will be your starting position.","Using both legs, jump forward landing with your feet next to your hands. Keep your head up as you do so.","Return to the starting position and immediately repeat the movement, continuing for 10-20 repetitions."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:pull","mechanic:compound"]},{id:"Hammer_Curls",name:"Hammer Curls",instructions:["Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.","The palms of the hands should be facing your torso. This will be your starting position.","Now, while holding your upper arm stationary, exhale and curl the weight forward while contracting the biceps. Continue to raise the weight until the biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief moment as you squeeze the biceps. Tip: Focus on keeping the elbow stationary and only moving your forearm.","After the brief pause, inhale and slowly begin the lower the dumbbells back down to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Hammer_Grip_Incline_DB_Bench_Press",name:"Hammer Grip Incline DB Bench Press",instructions:["Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.","Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.","Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.","As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions.","When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Hamstring_Stretch",name:"Hamstring Stretch",instructions:["Lie on your back with one leg extended above you, with the hip at ninety degrees. Keep the other leg flat on the floor.","Loop a belt, band, or rope over the ball of your foot. This will be your starting position.","Pull on the belt to create tension in the calves and hamstrings. Hold this stretch for 10-30 seconds, and repeat with the other leg."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Handstand_Push-Ups",name:"Handstand Push-Ups",instructions:["With your back to the wall bend at the waist and place both hands on the floor at shoulder width.","Kick yourself up against the wall with your arms straight. Your body should be upside down with the arms and legs fully extended. Keep your whole body as straight as possible. Tip: If doing this for the first time, have a spotter help you. Also, make sure that you keep facing the wall with your head, rather than looking down.","Slowly lower yourself to the ground as you inhale until your head almost touches the floor. Tip: It is of utmost importance that you come down slow in order to avoid head injury.","Push yourself back up slowly as you exhale until your elbows are nearly locked.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:[],level:"advanced",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Hanging_Leg_Raise",name:"Hanging Leg Raise",instructions:["Hang from a chin-up bar with both arms extended at arms length in top of you using either a wide grip or a medium grip. The legs should be straight down with the pelvis rolled slightly backwards. This will be your starting position.","Raise your legs until the torso makes a 90-degree angle with the legs. Exhale as you perform this movement and hold the contraction for a second or so.","Go back slowly to the starting position as you breathe in.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"advanced",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Hanging_Pike",name:"Hanging Pike",instructions:["Hang from a chin-up bar with your legs and feet together using an overhand grip (palms facing away from you) that is slightly wider than shoulder width. Tip: You may use wrist wraps in order to facilitate holding on to the bar.","Now bend your knees at a 90 degree angle and bring the upper legs forward so that the calves are perpendicular to the floor while the thighs remain parallel to it. This will be your starting position.","Pull your legs up as you exhale until you almost touch your shins with the bar above you. Tip: Try to straighten your legs as much as possible while at the top.","Lower your legs as slowly as possible until you reach the starting position. Tip: Avoid swinging and using momentum at all times.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"advanced",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Hip_Circles_prone",name:"Hip Circles (prone)",instructions:["Position yourself on your hands and knees on the ground. Maintaining good posture, raise one bent knee off of the ground. This will be your starting position.","Keeping the knee in a bent position, rotate the femur in an arc, attempting to make a big circle with your knee.","Perform this slowly for a number of repetitions, and repeat on the other side."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","mechanic:isolation","secondary:legs"]},{id:"Hip_Extension_with_Bands",name:"Hip Extension with Bands",instructions:["Secure one end of the band to the lower portion of a post and attach the other to one ankle.","Facing the attachment point of the band, hold on to the column to stabilize yourself.","Keeping your head and your chest up, move the resisted leg back as far as you can while keeping the knee straight.","Return the leg to the starting position."],muscleGroups:["glutes"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:legs"]},{id:"Hip_Flexion_with_Band",name:"Hip Flexion with Band",instructions:["Secure one end of the band to the lower portion of a post and attach the other to one ankle.","Face away from the attachment point of the band.","Keeping your head and your chest up, raise your knee up to 90 degrees and pause.","Return the leg to the starting position."],muscleGroups:["legs"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Hug_A_Ball",name:"Hug A Ball",instructions:["Seat yourself on the floor.","Straddle an exercise ball between both legs and lower your hips down toward the floor.","Hug your arms around the ball to support your body. Adjust your legs so that your feet are flat on the floor and your knees line up over your ankles. Keep a good grip on the ball so it doesn't roll away from you and send you back onto your buttocks."],muscleGroups:["back_posture"],equipment:["pilates_equipment"],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:legs","secondary:glutes"]},{id:"Hug_Knees_To_Chest",name:"Hug Knees To Chest",instructions:["Lie down on your back and pull both knees up to your chest.","Hold your arms under the knees, not over (that would put to much pressure on your knee joints).","Slowly pull the knees toward your shoulders. This also stretches your buttocks muscles."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:glutes"]},{id:"Hyperextensions_With_No_Hyperextension_Bench",name:"Hyperextensions With No Hyperextension Bench",instructions:["With someone holding down your legs, slide yourself down to the edge a flat bench until your hips hang off the end of the bench. Tip: Your entire upper body should be hanging down towards the floor. Also, you will be in the same position as if you were on a hyperextension bench but the range of motion will be shorter due to the height of the flat bench vs. that of the hyperextension bench.","With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.","Start bending forward slowly at the waist as far as you can while keeping your back flat. Inhale as you perform this movement. Keep moving forward until you almost touch the floor or you feel a nice stretch on the hamstrings (whichever comes first). Tip: Never round the back as you perform this exercise.","Slowly raise your torso back to the initial position as you exhale. Tip: Avoid the temptation to arch your back past a straight line. Also, do not swing the torso at any time in order to protect the back from injury.","Repeat for the recommended amount of repetitions."],muscleGroups:["back_posture"],equipment:[],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:glutes","secondary:legs"]},{id:"Inchworm",name:"Inchworm",instructions:["Stand with your feet close together. Keeping your legs straight, stretch down and put your hands on the floor directly in front of you. This will be your starting position.","Begin by walking your hands forward slowly, alternating your left and your right. As you do so, bend only at the hip, keeping your legs straight.","Keep going until your body is parallel to the ground in a pushup position.","Now, keep your hands in place and slowly take short steps with your feet, moving only a few inches at a time.","Continue walking until your feet are by hour hands, keeping your legs straight as you do so."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["mechanic:compound"]},{id:"Incline_Dumbbell_Bench_With_Palms_Facing_In",name:"Incline Dumbbell Bench With Palms Facing In",instructions:["Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.","Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.","Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.","As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions.","When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Incline_Dumbbell_Curl",name:"Incline Dumbbell Curl",instructions:["Sit back on an incline bench with a dumbbell in each hand held at arms length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.","While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second.","Slowly begin to bring the dumbbells back to starting position as your breathe in.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Incline_Dumbbell_Flyes",name:"Incline Dumbbell Flyes",instructions:["Hold a dumbbell on each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.","Extend your arms above you with a slight bend at the elbows.","Now rotate the wrists so that the palms of your hands are facing you. Tip: The pinky fingers should be next to each other. This will be your starting position.","As you breathe in, start to slowly lower the arms to the side while keeping the arms extended and while rotating the wrists until the palms of the hand are facing each other. Tip: At the end of the movement the arms will be by your side with the palms facing the ceiling.","As you exhale start to bring the dumbbells back up to the starting position by reversing the motion and rotating the hands so that the pinky fingers are next to each other again. Tip: Keep in mind that the movement will only happen at the shoulder joint and at the wrist. There is no motion that happens at the elbow joint.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Incline_Dumbbell_Flyes_-_With_A_Twist",name:"Incline Dumbbell Flyes - With A Twist",instructions:["Hold a dumbbell in each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.","Extend your arms above you with a slight bend at the elbows.","Now rotate the wrists so that the palms of your hands are facing you. Tip: The pinky fingers should be next to each other. This will be your starting position.","As you breathe in, start to slowly lower the arms to the side while keeping the arms extended and while rotating the wrists until the palms of the hand are facing each other. Tip: At the end of the movement the arms will be by your side with the palms facing the ceiling.","As you exhale start to bring the dumbbells back up to the starting position by reversing the motion and rotating the hands so that the pinky fingers are next to each other again. Tip: Keep in mind that the movement will only happen at the shoulder joint and at the wrist. There is no motion that happens at the elbow joint.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Incline_Dumbbell_Press",name:"Incline Dumbbell Press",instructions:["Lie back on an incline bench with a dumbbell in each hand atop your thighs. The palms of your hands will be facing each other.","Then, using your thighs to help push the dumbbells up, lift the dumbbells one at a time so that you can hold them at shoulder width.","Once you have the dumbbells raised to shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","Be sure to keep full control of the dumbbells at all times. Then breathe out and push the dumbbells up with your chest.","Lock your arms at the top, hold for a second, and then start slowly lowering the weight. Tip Ideally, lowering the weights should take about twice as long as raising them.","Repeat the movement for the prescribed amount of repetitions.","When you are done, place the dumbbells back on your thighs and then on the floor. This is the safest manner to release the dumbbells."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Incline_Hammer_Curls",name:"Incline Hammer Curls",instructions:["Seat yourself on an incline bench with a dumbbell in each hand. You should pressed firmly against he back with your feet together. Allow the dumbbells to hang straight down at your side, holding them with a neutral grip. This will be your starting position.","Initiate the movement by flexing at the elbow, attempting to keep the upper arm stationary.","Continue to the top of the movement and pause, then slowly return to the start position."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Incline_Inner_Biceps_Curl",name:"Incline Inner Biceps Curl",instructions:["Hold a dumbbell in each hand and lie back on an incline bench.","The dumbbells should be at arm's length hanging at your sides and your palms should be facing out. This will be your starting position.","Now as you exhale curl the weight outward and up while keeping your forearms in line with your side deltoids. Continue the curl until the dumbbells are at shoulder height and to the sides of your deltoids. Tip: The end of the movement should look similar to a double biceps pose.","After a second contraction at the top of the movement, start to inhale and slowly lower the weights back to the starting position using the same path used to bring them up.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["mechanic:isolation"]},{id:"Incline_Push-Up",name:"Incline Push-Up",instructions:["Stand facing bench or sturdy elevated platform. Place hands on edge of bench or platform, slightly wider than shoulder width.","Position forefoot back from bench or platform with arms and body straight. Arms should be perpendicular to body. Keeping body straight, lower chest to edge of box or platform by bending arms.","Push body up until arms are extended. Repeat."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Incline_Push-Up_Close-Grip",name:"Incline Push-Up Close-Grip",instructions:["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.","Place your hands next to one another on the bar.","Position your feet back from the bar with arms and body straight. This will be your starting position.","Keeping your body straight, lower your chest to the bar by bending the arms.","Return to the starting position by extending the elbows, pressing yourself back up."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Incline_Push-Up_Medium",name:"Incline Push-Up Medium",instructions:["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.","Place your hands on the bar, with your hands about shoulder width apart.","Position your feet back from the bar with arms and body straight. This will be your starting position.","Keeping your body straight, lower your chest to the bar by bending the arms.","Return to the starting position by extending the elbows, pressing yourself back up."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Incline_Push-Up_Reverse_Grip",name:"Incline Push-Up Reverse Grip",instructions:["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.","Place your hands on the bar palms up, with your hands about shoulder width apart.","Position your feet back from the bar with arms and body straight. This will be your starting position.","Keeping your body straight, lower your chest to the bar by bending the arms.","Return to the starting position by extending the elbows, pressing yourself back up."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Incline_Push-Up_Wide",name:"Incline Push-Up Wide",instructions:["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.","Place your hands on the bar, with your hands wider than shoulder width.","Position your feet back from the bar with arms and body straight. Your arms should be perpendicular to the body. This will be your starting position.","Keeping your body straight, lower your chest to the bar by bending the arms.","Return to the starting position by extending the elbows, pressing yourself back up."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Internal_Rotation_with_Band",name:"Internal Rotation with Band",instructions:["Choke the band around a post. The band should be at the same height as your elbow. Stand with your right side to the band a couple of feet away.","Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.","With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching away from your torso. This will be your starting position.","Execute the movement by rotating your arm in a forehand motion, keeping your elbow in place.","Continue as far as you are able, pause, and then return to the starting position."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["mechanic:isolation"]},{id:"Inverted_Row",name:"Inverted Row",instructions:["Position a bar in a rack to about waist height. You can also use a smith machine.","Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.","Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement.","Pause at the top of the motion, and return yourself to the start position.","Repeat for the desired number of repetitions."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:back_posture"]},{id:"Iron_Crosses_stretch",name:"Iron Crosses (stretch)",instructions:["Lie face down on the floor, with your arms extended out to your side, palms pressed to the floor. This will be your starting position.","To begin, flex one knee and bring that leg across the back of your body, attempting to touch it to the ground near the opposite hand.","Promptly return the leg to the starting postion, and quickly repeat with the other leg. Continue alternating for 10-20 repetitions."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:pull","mechanic:compound"]},{id:"Isometric_Chest_Squeezes",name:"Isometric Chest Squeezes",instructions:["While either seating or standing, bend your arms at a 90-degree angle and place the palms of your hands together in front of your chest. Tip: Your hands should be open with the palms together and fingers facing forward (perpendicular to your torso).","Push both hands against each other as you contract your chest. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.","Hold for the recommended number of seconds.","Now release the tension slowly.","Rest for the recommended amount of time and repeat."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:static","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Isometric_Neck_Exercise_-_Front_And_Back",name:"Isometric Neck Exercise - Front And Back",instructions:["With your head and neck in a neutral position (normal position with head erect facing forward), place both of your hands on the front side of your head.","Now gently push forward as you contract the neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.","Hold for the recommended number of seconds.","Now release the tension slowly.","Rest for the recommended amount of time and repeat with your hands placed on the back side of your head."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"strength",tags:["force:static","mechanic:isolation"]},{id:"Isometric_Neck_Exercise_-_Sides",name:"Isometric Neck Exercise - Sides",instructions:["With your head and neck in a neutral position (normal position with head erect facing forward), place your left hand on the left side of your head.","Now gently push towards the left as you contract the left neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.","Hold for the recommended number of seconds.","Now release the tension slowly.","Rest for the recommended amount of time and repeat with your right hand placed on the right side of your head."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"strength",tags:["force:static","mechanic:isolation"]},{id:"Isometric_Wipers",name:"Isometric Wipers",instructions:["Assume a push-up position, supporting your weight on your hands and toes while keeping your body straight. Your hands should be just outside of shoulder width. This will be your starting position.","Begin by shifting your body weight as far to one side as possible, allowing the elbow on that side to flex as you lower your body.","Reverse the motion by extending the flexed arm, pushing yourself up and then dropping to the other side.","Repeat for the desired number of repetitions."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Jackknife_Sit-Up",name:"Jackknife Sit-Up",instructions:["Lie flat on the floor (or exercise mat) on your back with your arms extended straight back behind your head and your legs extended also. This will be your starting position.","As you exhale, bend at the waist while simultaneously raising your legs and arms to meet in a jackknife position. Tip: The legs should be extended and lifted at approximately a 35-45 degree angle from the floor and the arms should be extended and parallel to your legs. The upper torso should be off the floor.","While inhaling, lower your arms and legs back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Janda_Sit-Up",name:"Janda Sit-Up",instructions:["Position your body on the floor in the basic sit-up position; knees to a ninety degree angle with feet flat on the floor and arms either crossed over your chest or to the sides. This will be your starting position.","As you strongly tighten your glutes and hamstrings, fill your lungs with air and in a slow (three to six second count) ascent, slowly exhale. Tip: It is important to tighten the glutes and hamstrings as this will cause the hip flexors to be inactivated in a process called reciprocal inhibition, which basically means that opposite muscles to the contracted ones will relax.","As you inhale, slowly go back in a controlled manner to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Knee_Across_The_Body",name:"Knee Across The Body",instructions:["Lie down on the floor with your right leg straight. Bend your left leg and lower it across your body, holding the knee down toward the floor with your right hand. (The knee doesn't need to touch the floor if you're tight.)","Place your left arm comfortably beside you and turn your head to the left. Imagine you have a weight tied to your tailbone. let your tailbone fall back toward the floor as your chest reaches in the opposite direction to stretch your lower back. Switch sides."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:legs","secondary:back_posture"]},{id:"Knee_Circles",name:"Knee Circles",instructions:["Stand with your legs together and hands by your waist.","Now move your knees in a circular motion as you breathe normally.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","mechanic:compound","secondary:legs"]},{id:"Knee_Tuck_Jump",name:"Knee Tuck Jump",instructions:["Begin in a comfortable standing position with your knees slightly bent. Hold your hands in front of you, palms down with your fingertips together at chest height. This will be your starting position.","Rapidly dip down into a quarter squat and immediately explode upward. Drive the knees towards the chest, attempting to touch them to the palms of the hands.","Jump as high as you can, raising your knees up, and then ensure a good land be re-extending your legs, absorbing impact through be allowing the knees to rebend."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Kneeling_Arm_Drill",name:"Kneeling Arm Drill",instructions:["This drill helps increase arm efficiency during the run. Begin kneeling, left foot in front, right knee down. Apply pressure through the front heel to keep your glutes and hamstrings activated.","Begin by blocking the arms in long, pendulum like swings. Close the arm angle, blocking with the arms as you would when jogging, progressing to a run and finally a sprint.","As soon as your hands pass the hip, accelerate them forward during the sprinting motion to move them as quickly as possible.","Switch knees and repeat."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:pull","secondary:core_abs"]},{id:"Kneeling_Forearm_Stretch",name:"Kneeling Forearm Stretch",instructions:["Start by kneeling on a mat with your palms flat and your fingers pointing back toward your knees.","Slowly lean back keeping your palms flat on the floor until you feel a stretch in your wrists and forearms. Hold for 20-30 seconds."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Kneeling_Hip_Flexor",name:"Kneeling Hip Flexor",instructions:["Kneel on a mat and bring your right knee up so the bottom of your foot is on the floor and extend your left leg out behind you so the top of your foot is on the floor.","Shift your weight forward until you feel a stretch in your hip. Hold for 15 seconds, then repeat for your other side."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:legs"]},{id:"Lateral_Bound",name:"Lateral Bound",instructions:["Assume a half squat position facing 90 degrees from your direction of travel. This will be your starting position.","Allow your lead leg to do a countermovement inward as you shift your weight to the outside leg.","Immediately push off and extend, attempting to bound to the side as far as possible.","Upon landing, immediately push off in the opposite direction, returning to your original start position.","Continue back and forth for several repetitions."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Lateral_Raise_-_With_Bands",name:"Lateral Raise - With Bands",instructions:["To begin, stand on an exercise band so that tension begins at arm's length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on the sides of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.","Use your side shoulders to lift the handles to the sides as you exhale. Continue to lift the handles until they are slightly above parallel. Tip: As you lift the handles, slightly tilt the hand as if you were pouring water and keep your arms extended. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the handles back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Leg_Lift",name:"Leg Lift",instructions:["While standing up straight with both feet next to each other at around shoulder width, grab a sturdy surface such as the sides of a squat rack or the top of a chair to brace yourself and keep balance.","With or without an ankle weight, lift one leg behind you as if performing a leg curl but standing up while keeping the other leg straight. Breathe out as you perform this movement.","Slowly bring the raised leg back to the floor as you breathe in.","Repeat for the recommended amount of repetitions.","Repeat the movement with the opposite leg."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation","secondary:legs"]},{id:"Leg_Pull-In",name:"Leg Pull-In",instructions:["Lie on an exercise mat with your legs extended and your hands either palms facing down next to you or under your glutes. Tip: My preference is with the hands next to me. This will be your starting position.","Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue the motion until your knees are around chest level. Contract your abs as you execute this movement and hold for a second at the top. Tip: As you perform the motion, the lower legs (calves) should always remain parallel to the floor.","Return to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Leg-Up_Hamstring_Stretch",name:"Leg-Up Hamstring Stretch",instructions:["Lie flat on your back, bend one knee, and put that foot flat on the floor to stabilize your spine.","Extend the other leg in the air. If you're tight, you wont be able to straighten it. That's okay. Extend the knee so that the sole of the lifted foot faces the ceiling (or as close as you can get it).","Slowly straighten the legs as much as possible and then pull the leg toward your nose. Switch sides."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:push","mechanic:isolation"]},{id:"Linear_3-Part_Start_Technique",name:"Linear 3-Part Start Technique",instructions:["This drill helps you accelerate as quickly as possible into a sprint from a dead stop. It helps to use a line to start from. Begin with two feet on the line. Place your left foot with the toe next to your right ankle. Place your right foot 4-6 inches behind the left.","Place your right hand onto the line, and thing bring your nose close to your left knee.","Squat down as you lean foward, your head being lower than your hips and your weight loaded onto the left leg. This will be your starting position.","Take your left hand up so that it is parallel to the ground, pointing behind you, and explode out when ready."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs"]},{id:"Linear_Acceleration_Wall_Drill",name:"Linear Acceleration Wall Drill",instructions:["Lean at around 45 degrees against a wall. Your feet should be together, glutes contracted.","Begin by lifting your right knee quickly, pausing, and then driving it straight down into the ground.","Switch legs, raising the opposite knee, and then attacking the ground straight down.","Repeat once more with your right leg, and as soon as the right foot strikes the ground hammer them out rapidly, alternating left and right as fast as you can."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Looking_At_Ceiling",name:"Looking At Ceiling",instructions:["Kneel on the floor, holding your heels with both hands.","Lift your buttocks up and forward while bringing your head back to look up at the ceiling, to give an arch in your back."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Lower_Back_Curl",name:"Lower Back Curl",instructions:["Lie on your stomach with your arms out to your sides. This will be your starting position.","Using your lower back muscles, extend your spine lifting your chest off of the ground. Do not use your arms to push yourself up. Keep your head up during the movement. Repeat for 10-20 repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static"]},{id:"Lying_Crossover",name:"Lying Crossover",instructions:["Lie on your back with your legs extended.","Cross one leg over your body with the knee bent, attempting to touch the knee to the ground. Your partner should kneel beside you, holding your shoulder down with one hand and controlling the crossed leg with the other. this will be your starting position.","Attempt to raise the bent knee off of the ground as your partner prevents any actual movement.","After 10-20 seconds, relax the leg as your partner gently presses the knee towards the floor. Repeat with the other side."],muscleGroups:["legs"],equipment:[],level:"advanced",category:"stretching",tags:["force:static"]},{id:"Lying_Dumbbell_Tricep_Extension",name:"Lying Dumbbell Tricep Extension",instructions:["Lie on a flat bench while holding two dumbbells directly in front of you. Your arms should be fully extended at a 90-degree angle from your torso and the floor. The palms should be facing in and the elbows should be tucked in. This is the starting position.","As you breathe in and you keep the upper arms stationary with the elbows in, slowly lower the weight until the dumbbells are near your ears.","At that point, while keeping the elbows in and the upper arms stationary, use the triceps to bring the weight back up to the starting position as you breathe out.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:isolation","secondary:upper_body"]},{id:"Lying_Glute",name:"Lying Glute",instructions:["Lie on your back with your partner kneeling beside you.","Flex the hip of one leg, raising it off of the floor. Rotate the leg so the foot is over the opposite hip, the lower leg perpendicular to your body. Your partner should hold the knee and ankle in place. This will be your starting position.","Attempt to push your leg towards your partner, who should be preventing any actual movement of the leg.","After 10-20 seconds, completely relax as your partner gently pushes the ankle and knee towards your chest. Be sure to inform your helper when the stretch is adequate to prevent injury or overstretching."],muscleGroups:["glutes"],equipment:[],level:"advanced",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Lying_One-Arm_Lateral_Raise",name:"Lying One-Arm Lateral Raise",instructions:["While holding a dumbbell in one hand, lay with your chest down on a flat bench. The other hand can be used to hold to the leg of the bench for stability.","Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.","Now raise the arm with the dumbbell to the side until your elbow is at shoulder height and your arm is roughly parallel to the floor as you exhale. Tip: Maintain your arm perpendicular to the torso while keeping your arm extended throughout the movement. Also, keep the contraction at the top for a second.","Slowly lower the dumbbell to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Lying_Prone_Quadriceps",name:"Lying Prone Quadriceps",instructions:["Lay face down on the floor with your partner kneeling beside you. Flex one knee and raise that leg off the ground, attempting to touch your glutes with your foot. Your partner should hold the knee and ankle. This will be your starting position.","Attempt to extend your knee while your partner prevents any actual movement.","After 10-20 seconds, relax your muscles as your partner gently pushes the foot towards your glutes, further stretching the quadriceps and hip flexors.","After 10-20 seconds, switch sides."],muscleGroups:["legs"],equipment:[],level:"advanced",category:"stretching",tags:[]},{id:"Lying_Rear_Delt_Raise",name:"Lying Rear Delt Raise",instructions:["While holding a dumbbell in each hand, lay with your chest down on a flat bench.","Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.","Now raise the arms to the side until your elbows are at shoulder height and your arms are roughly parallel to the floor as you exhale. Tip: Maintain your arms perpendicular to the torso while keeping them extended throughout the movement. Also, keep the contraction at the top for a second.","Slowly lower the dumbbells to the starting position as you inhale.","Repeat for the recommended amount of repetitions and then switch to the other arm."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Lying_Supine_Dumbbell_Curl",name:"Lying Supine Dumbbell Curl",instructions:["Lie down on a flat bench face up while holding a dumbbell in each arm on top of your thighs.","Bring the dumbbells to the sides with the arms extended and the palms of the hands facing your thighs (neutral grip).","While keeping the arms close to your torso and elbows in, slowly lower your arms (as you keep them extended with a slight bend at the elbows) as far down towards the floor as you can go. Once you cannot go down any further, lock your upper arms in that position and that will be your starting position.","As you breathe out, slowly begin to curl the weights up as you simultaneously rotate your wrists so that the palms of the hands face up. Continue curling the weight until your biceps are fully contracted and squeeze hard at the top position for a second. Tip: Only the forearms should move. Upper arms should remain stationary and elbows should stay in throughout the movement.","Return back to the starting position very slowly."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Medicine_Ball_Chest_Pass",name:"Medicine Ball Chest Pass",instructions:["You will need a partner for this exercise. Lacking one, this movement can be performed against a wall.","Begin facing your partner holding the medicine ball at your torso with both hands.","Pull the ball to your chest, and reverse the motion by extending through the elbows. For sports applications, you can take a step as you throw.","Your partner should catch the ball, and throw it back to you.","Receive the throw with both hands at chest height."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Medicine_Ball_Full_Twist",name:"Medicine Ball Full Twist",instructions:["For this exercise you will need a medicine ball and a partner. Stand back to back with your partner, spaced 2-3 feet apart. This will be your starting position.","Hold the ball in front of the trunk. Open the hips and turn the shoulders at the same time as your partner.","For full rotation, you and your partner should twist in the same direction, i.e. counter-clockwise.","Pass the ball to your partner, and both of you can now twist in the opposite direction to repeat the procedure."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:pull","mechanic:compound","secondary:upper_body"]},{id:"Medicine_Ball_Scoop_Throw",name:"Medicine Ball Scoop Throw",instructions:["Assume a semisquat stance with a medicine ball in your hands. Your arms should hang so the ball is near your feet.","Begin by thrusting the hips forward as you extend through the legs, jumping up.","As you do, swing your arms up and over your head, keeping them extended, releasing the ball at the peak of your movement. The goal is to throw the ball the greatest distance behind you."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:legs"]},{id:"Middle_Back_Shrug",name:"Middle Back Shrug",instructions:["Lie facedown on an incline bench while holding a dumbbell in each hand. Your arms should be fully extended hanging down and pointing towards the floor. The palms of your hands should be facing each other. This will be your starting position.","As you exhale, squeeze your shoulder blades together and hold the contraction for a full second. Tip: This movement is just like the reverse action of a hug, or trying to perform rear laterals as if you had no arms.","As you inhale go back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["back_posture"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Middle_Back_Stretch",name:"Middle Back Stretch",instructions:["Stand so your feet are shoulder width apart and your hands are on your hips.","Twist at your waist until you feel a stretch. Hold for 10 to 15 seconds, then twist to the other side."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:core_abs","secondary:back_posture"]},{id:"Monster_Walk",name:"Monster Walk",instructions:["Place a band around both ankles and another around both knees. There should be enough tension that they are tight when your feet are shoulder width apart.","To begin, take short steps forward alternating your left and right foot.","After several steps, do just the opposite and walk backward to where you started."],muscleGroups:["legs"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Mountain_Climbers",name:"Mountain Climbers",instructions:["Begin in a pushup position, with your weight supported by your hands and toes. Flexing the knee and hip, bring one leg until the knee is approximately under the hip. This will be your starting position.","Explosively reverse the positions of your legs, extending the bent leg until the leg is straight and supported by the toe, and bringing the other foot up with the hip and knee flexed. Repeat in an alternating fashion for 20-30 seconds."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:pull","mechanic:compound","secondary:upper_body","secondary:legs"]},{id:"Moving_Claw_Series",name:"Moving Claw Series",instructions:["This move helps prepare your running form to help you excel at sprinting. As you run, be sure to flex the knee, aiming to kick your glutes as the hip extends.","Reload the quad as the leg moves back forward, attacking the ground on the next step.","Ensure that as you run, you block with the arms, punching through in a rapid 1-2 motion."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["mechanic:compound","secondary:legs"]},{id:"Natural_Glute_Ham_Raise",name:"Natural Glute Ham Raise",instructions:["Using the leg pad of a lat pulldown machine or a preacher bench, position yourself so that your ankles are under the pads, knees on the seat, and you are facing away from the machine. You should be upright and maintaining good posture.","This will be your starting position. Lower yourself under control until your knees are almost completely straight.","Remaining in control, raise yourself back up to the starting position.","If you are unable to complete a rep, use a band, a partner, or push off of a box to aid in completing a repetition."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:legs","secondary:glutes","secondary:back_posture"]},{id:"Oblique_Crunches",name:"Oblique Crunches",instructions:["Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put one hand beside your head and the other to the side against the floor.","Make sure your feet are elevated and resting on a flat surface.","Now lift the shoulder in which your hand is touching your head.","Simply elevate your shoulder and body upward until you touch your knee. For example, if you have your right hand besides your head, then you want to elevate your body upwards until your right elbow touches your left knee. The same variation can be applied doing the inverse and using your left elbow to touch your right knee.","After your knee touches your elbow, lower your body until you have reached the starting position.","Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (upward) part of the exercise.","Continue alternating in this manner until all of the recommended repetitions for each side have been completed."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Oblique_Crunches_-_On_The_Floor",name:"Oblique Crunches - On The Floor",instructions:["Start out by lying on your right side with your legs lying on top of each other. Make sure your knees are bent a little bit.","Place your left hand behind your head.","Once you are in this set position, begin by moving your left elbow up as you would perform a normal crunch except this time the main emphasis is on your obliques.","Crunch as high as you can, hold the contraction for a second and then slowly drop back down into the starting position.","Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (elevation) part of the exercise."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"On_Your_Side_Quad_Stretch",name:"On Your Side Quad Stretch",instructions:["Start off by lying on your right side, with your right knee bent at a 90-degree angle resting on the floor in front of you (this stabilizes the torso).","Bend your left knee behind you and hold your left foot with your left hand. To stretch your hip flexor, press your left hip forward as you push your left foot back into your hand. Switch sides."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"One_Arm_Against_Wall",name:"One Arm Against Wall",instructions:["From a standing position, place a bent arm against a wall or doorway.","Slowly lean toward your arm until you feel a stretch in your lats."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"One_Arm_Dumbbell_Bench_Press",name:"One Arm Dumbbell Bench Press",instructions:["Lie down on a flat bench with a dumbbell in one hand on top of your thigh.","By using your thigh to help you get the dumbbell up, clean the dumbbell up so that you can hold it in front of you at shoulder width. Use the hand you are not lifting with to help position the dumbbell over you properly.","Once at shoulder width, rotate your wrist forward so that the palm of your hand is facing away from you. This will be your starting position.","Bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbell at all times. Tip: Use the hand that you are not lifting with to help keep the dumbbell balance as you may struggle a bit at first. Only use your non-lifting hand if it is needed. Otherwise, keep it resting to the side.","As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions of your training program.","Switch arms and repeat the movement."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"One_Arm_Dumbbell_Preacher_Curl",name:"One Arm Dumbbell Preacher Curl",instructions:["Grab a dumbbell with the right arm and place the upper arm on top of the preacher bench or the incline bench. The dumbbell should be held at shoulder length. This will be your starting position.","As you breathe in, slowly lower the dumbbell until your upper arm is extended and the biceps is fully stretched.","As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the dumbbell is at shoulder height. Again, remember that to ensure full contraction you need to bring that small finger higher than the thumb.","Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions.","Switch arms and repeat the movement."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"One_Arm_Pronated_Dumbbell_Triceps_Extension",name:"One Arm Pronated Dumbbell Triceps Extension",instructions:["Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your feet as a pronated grip is required to perform this exercise.","Place your non lifting hand on your bicep for support.","Slowly begin to lower the dumbbell down as you breathe in.","Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).","Repeat until you have performed your set repetitions.","Switch arms and repeat the movement."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"One_Arm_Supinated_Dumbbell_Triceps_Extension",name:"One Arm Supinated Dumbbell Triceps Extension",instructions:["Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your face as a supinated grip is required to perform this exercise.","Place your non lifting hand on your bicep for support.","Slowly begin to lower the dumbbell down as you breathe in.","Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).","Repeat until you have performed your set repetitions.","Switch arms and repeat the movement.","Switch arms again and repeat the movement."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"One_Half_Locust",name:"One Half Locust",instructions:["Lie facedown on the floor.","Put your left hand under your left hipbone to pad your hip and pubic bone.","Bend your right knee so you can hold the foot in your right hand.","Lift the foot in the air and simultaneously lift your shoulders off the floor. This also stretches the right hip flexor and the chest and shoulders. Switch sides. If it doesn't bother your back, you can try it with both arms and legs at the same time."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:core_abs","secondary:arms","secondary:upper_body"]},{id:"One_Knee_To_Chest",name:"One Knee To Chest",instructions:["Start off by lying on the floor.","Extend one leg straight and pull the other knee to your chest. Hold under the knee joint to protect the kneecap.","Gently tug that knee toward your nose.","Switch sides. This stretches the buttocks and lower back of the bent leg and the hip flexor of the straight leg."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:compound","secondary:legs","secondary:back_posture"]},{id:"One-Arm_Dumbbell_Row",name:"One-Arm Dumbbell Row",instructions:["Choose a flat bench and place a dumbbell on each side of it.","Place the right leg on top of the end of the bench, bend your torso forward from the waist until your upper body is parallel to the floor, and place your right hand on the other end of the bench for support.","Use the left hand to pick up the dumbbell on the floor and hold the weight while keeping your lower back straight. The palm of the hand should be facing your torso. This will be your starting position.","Pull the resistance straight up to the side of your chest, keeping your upper arm close to your side and keeping the torso stationary. Breathe out as you perform this step. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. Also, make sure that the force is performed with the back muscles and not the arms. Finally, the upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the dumbbell; therefore do not try to pull the dumbbell up using the forearms.","Lower the resistance straight down to the starting position. Breathe in as you perform this step.","Repeat the movement for the specified amount of repetitions.","Switch sides and repeat again with the other arm."],muscleGroups:["back_posture"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture","secondary:upper_body"]},{id:"One-Arm_Flat_Bench_Dumbbell_Flye",name:"One-Arm Flat Bench Dumbbell Flye",instructions:["Lie down on a flat bench with a dumbbell in one hand resting on top of your thigh. The palm of your hand with the dumbbell in it should be at a neutral grip.","By using your thighs to help you get the dumbbell up, clean the dumbbell so that you can hold it in front of you with your lifting arm being fully extended. Remember to maintain a neutral grip with this exercise. Your non lifting hand should be to the side holding the flat bench for better support. This will be your starting position.","Your arm with the weight should have a slight bend on your elbow in order to prevent stress at the biceps tendon. Begin by lowering your arm with the weight in it out in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, your lifting arm should remain stationary; the movement should only occur at the shoulder joint.","Return your lifting arm back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.","Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions.","Switch arms and repeat the exercise."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"One-Arm_Incline_Lateral_Raise",name:"One-Arm Incline Lateral Raise",instructions:["Lie down sideways on an incline bench press with a dumbbell in the hand. Make sure the shoulder is pressing against the incline bench and the arm is lying across your body with the palm around your navel.","Hold a dumbbell in your uppermost arm while keeping it extended in front of you parallel to the floor. This is your starting position.","While keeping the dumbbell parallel to the floor at all times, perform a lateral raise. Your arm should travel straight up until it is pointing at the ceiling. Tip: Exhale as you perform this movement. Hold the dumbbell in the position and feel the contraction in the shoulders for a second.","While inhaling lower the weight across your body back into the starting position.","Repeat the movement for the prescribed amount of repetitions.","Switch arms and repeat the movement."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"One-Arm_Medicine_Ball_Slam",name:"One-Arm Medicine Ball Slam",instructions:["Start in a standing position with a staggered, athletic stance. Hold a medicine ball in one hand, on the same side as your back leg. This will be your starting position.","Begin by winding the arm, raising the medicine ball above your head. As you do so, extend through the hips, knees, and ankles to load up for the slam.","At peak extension, flex the shoulders, spine, and hips to throw the ball hard into the ground directly in front of you.","Catch the ball on the bounce and continue for the desired number of repetitions."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:back_posture","secondary:upper_body"]},{id:"One-Arm_Side_Laterals",name:"One-Arm Side Laterals",instructions:["Pick a dumbbell and place it in one of your hands. Your non lifting hand should be used to grab something steady such as an incline bench press. Lean towards your lifting arm and away from the hand that is gripping the incline bench as this will allow you to keep your balance.","Stand with a straight torso and have the dumbbell by your side at arm's length with the palm of the hand facing you. This will be your starting position.","While maintaining the torso stationary (no swinging), lift the dumbbell to your side with a slight bend on the elbow and your hand slightly tilted forward as if pouring water in a glass. Continue to go up until you arm is parallel to the floor. Exhale as you execute this movement and pause for a second at the top.","Lower the dumbbell back down slowly to the starting position as you inhale.","Repeat for the recommended amount of repetitions.","Switch arms and repeat the exercise."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Overhead_Slam",name:"Overhead Slam",instructions:["Hold a medine ball with both hands and stand with your feet at shoulder width. This will be your starting position.","Initiate the countermovement by raising the ball above your head and fully extending your body.","Reverse the motion, slamming the ball into the ground directly in front of you as hard as you can.","Receive the ball with both hands on the bounce and repeat the movement."],muscleGroups:["back_posture"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:pull","mechanic:compound"]},{id:"Overhead_Stretch",name:"Overhead Stretch",instructions:["Standing straight up, lace your fingers together and open your palms to the ceiling. Keep your shoulders down as you extend your arms up.","To create a full torso stretch, pull your tailbone down and stabilize your torso as you do this. Stretch the muscles on both the front and the back of the torso."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:compound","secondary:upper_body","secondary:arms","secondary:back_posture"]},{id:"Overhead_Triceps",name:"Overhead Triceps",instructions:["Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your elbow and wrist. This will be your starting position.","Attempt to extend the arm straight into the air as your partner prevents you from doing actually doing so.","After 10-20 seconds, relax the arm and allow your partner to further stretch the tricep by applying gentle pressure to the wrist. Hold for 10-20 seconds, and then switch sides."],muscleGroups:["arms"],equipment:[],level:"advanced",category:"stretching",tags:["force:static","secondary:back_posture"]},{id:"Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench",name:"Palms-Down Dumbbell Wrist Curl Over A Bench",instructions:["Start out by placing two dumbbells on one side of a flat bench.","Kneel down on both of your knees so that your body is facing the flat bench.","Use your arms to grab both of the dumbbells with a pronated grip (palms facing down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.","Start out by curling your wrist upwards and exhaling.","Slowly lower your wrists back down to the starting position while inhaling.","Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench",name:"Palms-Up Dumbbell Wrist Curl Over A Bench",instructions:["Start out by placing two dumbbells on one side of a flat bench.","Kneel down on both of your knees so that your body is facing the flat bench.","Use your arms to grab both of the dumbbells with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.","Start out by curling your wrist upwards and exhaling.","Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise.","Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Pelvic_Tilt_Into_Bridge",name:"Pelvic Tilt Into Bridge",instructions:["Lie down with your feet on the floor, heels directly under your knees.","Lift only your tailbone to the ceiling to stretch your lower back. (Don't lift the entire spine yet.) Pull in your stomach.","To go into a bridge, lift the entire spine except the neck."],muscleGroups:["back_posture"],equipment:[],level:"intermediate",category:"stretching",tags:["force:static","mechanic:compound"]},{id:"Physioball_Hip_Bridge",name:"Physioball Hip Bridge",instructions:["Lay on a ball so that your upper back is on the ball with your hips unsupported. Both feet should be flat on the floor, hip width apart or wider. This will be your starting position.","Begin by extending the hips using your glutes and hamstrings, raising your hips upward as you bridge.","Pause at the top of the motion and return to the starting position."],muscleGroups:["glutes"],equipment:["pilates_equipment"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:legs"]},{id:"Plank",name:"Plank",instructions:["Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder.","Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:static","mechanic:isolation"]},{id:"Plie_Dumbbell_Squat",name:"Plie Dumbbell Squat",instructions:["Hold a dumbbell at the base with both hands and stand straight up. Move your legs so that they are wider than shoulder width apart from each other with your knees slightly bent.","Your toes should be facing out. Note: Your arms should be stationary while performing the exercise. This is the starting position.","Slowly bend the knees and lower your legs until your thighs are parallel to the floor. Make sure to inhale as this is the eccentric part of the exercise.","Press mainly with the heel of the foot to bring the body back to the starting position while exhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:legs","secondary:glutes"]},{id:"Plyo_Push-up",name:"Plyo Push-up",instructions:["Move into a prone position on the floor, supporting your weight on your hands and toes.","Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.","Descend by flexing at the elbow, lowering your chest towards the ground.","At the bottom, reverse the motion by pushing yourself up through elbow extension as quickly as possible. Attempt to push your upper body up until your hands leave the ground.","Return to the starting position and repeat the exercise.","For added difficulty, add claps into the movement while you are air borne."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Power_Partials",name:"Power Partials",instructions:["Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.","The palms of the hands should be facing your torso. Your feet should be about shoulder width apart. This will be your starting position.","Keeping your arms straight and the torso stationary, lift the weights out to your sides until they are about shoulder level height while exhaling.","Feel the contraction for a second and begin to lower the weights back down to the starting position while inhaling. Tip: Keep the palms facing down with the little finger slightly higher while lifting and lowering the weights as it will concentrate the stress on your shoulders mainly.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Preacher_Hammer_Dumbbell_Curl",name:"Preacher Hammer Dumbbell Curl",instructions:["Place the upper part of both arms on top of the preacher bench as you hold a dumbbell in each hand with the palms facing each other (neutral grip).","As you breathe in, slowly lower the dumbbells until your upper arm is extended and the biceps is fully stretched.","As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the dumbbells are at shoulder height.","Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Prone_Manual_Hamstring",name:"Prone Manual Hamstring",instructions:["You will need a partner for this exercise. Lay face down with your legs straight. Your assistant will place their hand on your heel.","To begin, flex the knee to curl your leg up. Your partner should provide resistance, starting light and increasing the pressure as the movement is completed. Communicate with your partner to monitor appropriate resistance levels.","Pause at the top, returning the leg to the starting position as your partner provides resistance going the other direction."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"strength",tags:["force:static","mechanic:isolation"]},{id:"Pullups",name:"Pullups",instructions:["Grab the pull-up bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.","As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.","Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.","After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.","Repeat this motion for the prescribed amount of repetitions."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture"]},{id:"Push_Up_to_Side_Plank",name:"Push Up to Side Plank",instructions:["Get into pushup position on the toes with your hands just outside of shoulder width.","Perform a pushup by allowing the elbows to flex. As you descend, keep your body straight.","Do one pushup and as you come up, shift your weight on the left side of the body, twist to the side while bringing the right arm up towards the ceiling in a side plank.","Lower the arm back to the floor for another pushup and then twist to the other side.","Repeat the series, alternating each side, for 10 or more reps."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Push-Up_Wide",name:"Push-Up Wide",instructions:["With your hands wide apart, support your body on your toes and hands in a plank position. Your elbows should be extended and your body straight. Do not allow your hips to sag. This will be your starting position.","To begin, allow the elbows to flex, lowering your chest to the floor as you inhale.","Using your pectoral muscles, press your upper body back up to the starting position by extending the elbows. Exhale as you perform this step.","After pausing at the contracted position, repeat the movement for the prescribed amount of repetitions."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["mechanic:compound","secondary:core_abs","secondary:upper_body","secondary:arms"]},{id:"Push-Ups_-_Close_Triceps_Position",name:"Push-Ups - Close Triceps Position",instructions:["Lie on the floor face down and place your hands closer than shoulder width for a close hand position. Make sure that you are holding your torso up at arms' length.","Lower yourself until your chest almost touches the floor as you inhale.","Using your triceps and some of your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],muscleGroups:["arms"],equipment:[],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Push-Ups_With_Feet_Elevated",name:"Push-Ups With Feet Elevated",instructions:["Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.","Place your toes on top of a flat bench. This will allow your body to be elevated. Note: The higher the elevation of the flat bench, the higher the resistance of the exercise is.","Lower yourself until your chest almost touches the floor as you inhale.","Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Push-Ups_With_Feet_On_An_Exercise_Ball",name:"Push-Ups With Feet On An Exercise Ball",instructions:["Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.","Place your toes on top of an exercise ball. This will allow your body to be elevated.","Lower yourself until your chest almost touches the floor as you inhale.","Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Pushups",name:"Pushups",instructions:["Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length.","Next, lower yourself downward until your chest almost touches the floor as you inhale.","Now breathe out and press your upper body back up to the starting position while squeezing your chest.","After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Pushups_Close_and_Wide_Hand_Positions",name:"Pushups (Close and Wide Hand Positions)",instructions:["Lie on the floor face down and body straight with your toes on the floor and the hands wider than shoulder width for a wide hand position and closer than shoulder width for a close hand position. Make sure you are holding your torso up at arms length.","Lower yourself until your chest almost touches the floor as you inhale.","Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Pyramid",name:"Pyramid",instructions:["Start off by rolling your torso forward onto the ball so your hips rest on top of the ball and become the highest point of your body.","Rest your hands and feet on the floor. Your arms and legs can be slightly bent or straight, depending on the size of the ball, your flexibility, and the length of your limbs. This also helps develop stabilizing strength in your torso and shoulders."],muscleGroups:["back_posture"],equipment:["pilates_equipment"],level:"beginner",category:"stretching",tags:["force:static","secondary:upper_body"]},{id:"Rear_Leg_Raises",name:"Rear Leg Raises",instructions:["Place yourself on your hands knees on an exercise mat. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.","Extend one leg up and behind you. The knee and hip should both extend. Repeat for 5-10 repetitions, and then switch sides."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:push"]},{id:"Return_Push_from_Stance",name:"Return Push from Stance",instructions:["You will need a partner for this drill.","Begin in an athletic 2 or 3 point stance.","At the signal, move into a position to receive the pass from your partner.","Catch the medicine ball with both hands and immediately throw it back to your partner.","You can modify this drill by running different routes."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Reverse_Crunch",name:"Reverse Crunch",instructions:["Lie down on the floor with your legs fully extended and arms to the side of your torso with the palms on the floor. Your arms should be stationary for the entire exercise.","Move your legs up so that your thighs are perpendicular to the floor and feet are together and parallel to the floor. This is the starting position.","While inhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the floor. At the end of this movement your knees will be touching your chest.","Hold the contraction for a second and move your legs back to the starting position while exhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Reverse_Flyes",name:"Reverse Flyes",instructions:["To begin, lie down on an incline bench with the chest and stomach pressing against the incline. Have the dumbbells in each hand with the palms facing each other (neutral grip).","Extend the arms in front of you so that they are perpendicular to the angle of the bench. The legs should be stationary while applying pressure with the ball of your toes. This is the starting position.","Maintaining the slight bend of the elbows, move the weights out and away from each other (to the side) in an arc motion while exhaling. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.","The arms should be elevated until they are parallel to the floor.","Feel the contraction and slowly lower the weights back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Reverse_Flyes_With_External_Rotation",name:"Reverse Flyes With External Rotation",instructions:["To begin, lie down on an incline bench set at a 30-degree angle with the chest and stomach pressing against the incline.","Have the dumbbells in each hand with the palms facing down to the floor. Your arms should be in front of you so that they are perpendicular to the angle of the bench. Tip: Your elbows should have a slight bend. The legs should be stationary while applying pressure with the ball of your toes (your heels should not be touching the floor). This is the starting position.","Maintaining the slight bend of the elbows, move the weights out and away from each other in an arc motion while exhaling.","As you lift the weight, your wrist should externally rotate by 90-degrees so that you go from a palms down (pronated) grip to a palms facing each other (neutral) grip. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.","The arms should be elevated until they are level with the head.","Feel the contraction and slowly lower the weights back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Rocket_Jump",name:"Rocket Jump",instructions:["Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.","To initiate the move, squat down halfway and explode back up as high as possible.","Fully extend your entire body, reaching overhead as far as possible. As you land, absorb your impact through the legs."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs"]},{id:"Runners_Stretch",name:"Runner's Stretch",instructions:["It's easiest to get into this stretch if you start standing up, put one leg behind you, and slowly lower your torso down to the floor.","Keep the front heel on the floor (if it lifts up, scoot your other leg further back).","Place your hands on either side of your front leg. To get more out of this stretch, push your butt up toward the ceiling, and then gradually lower it back toward the floor. You'll Stretch the hip flexor of the back leg and the hamstring and buttocks of the front."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Russian_Twist",name:"Russian Twist",instructions:["Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.","Elevate your upper body so that it creates an imaginary V-shape with your thighs. Your arms should be fully extended in front of you perpendicular to your torso and with the hands clasped. This is the starting position.","Twist your torso to the right side until your arms are parallel with the floor while breathing out.","Hold the contraction for a second and move back to the starting position while breathing out. Now move to the opposite side performing the same techniques you applied to the right side.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:back_posture"]},{id:"Scapular_Pull-Up",name:"Scapular Pull-Up",instructions:["Take a pronated grip on a pull-up bar.","From a hanging position, raise yourself a few inches without using your arms. Do this by depressing your shoulder girdle in a reverse shrugging motion.","Pause at the completion of the movement, and then slowly return to the starting position before performing more repetitions."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:back_posture"]},{id:"Scissor_Kick",name:"Scissor Kick",instructions:["To begin, lie down with your back pressed against the floor or on an exercise mat (optional). Your arms should be fully extended to the sides with your palms facing down. Note: The arms should be stationary the entire time.","With a slight bend at the knees, lift your legs up so that your heels are about 6 inches off the ground. This is the starting position.","Now lift your left leg up to about a 45 degree angle while your right leg is lowered until the heel is about 2-3 inches from the ground.","Switch movements by raising your right leg up and lowering your left leg. Remember to breathe while performing this exercise.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","mechanic:isolation"]},{id:"Scissors_Jump",name:"Scissors Jump",instructions:["Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.","Ensure that the front knee is over the midline of the foot. Extending through both legs, jump as high as possible, swinging your arms to gain lift.","As you jump as high as you can, switch the position of your legs, moving your front leg to the back and the rear leg to the front.","As you land, absorb the impact through the legs by adopting the lunge position, and repeat."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:glutes","secondary:legs"]},{id:"Seated_Bent-Over_One-Arm_Dumbbell_Triceps_Extension",name:"Seated Bent-Over One-Arm Dumbbell Triceps Extension",instructions:["Sit down at the end of a flat bench with a dumbbell in one arm using a neutral grip (palms of the hand facing you).","Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.","The upper arm with the dumbbell should be close to the torso and aligned with it (lifted up until it is parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights). Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.","Keeping the upper arm stationary, use the triceps to lift the weight as you exhale until the forearm is parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.","After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale.","Repeat the movement for the prescribed amount of repetitions.","Switch arms and repeat the exercise."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Seated_Bent-Over_Rear_Delt_Raise",name:"Seated Bent-Over Rear Delt Raise",instructions:["Place a couple of dumbbells looking forward in front of a flat bench.","Sit on the end of the bench with your legs together and the dumbbells behind your calves.","Bend at the waist while keeping the back straight in order to pick up the dumbbells. The palms of your hands should be facing each other as you pick them. This will be your starting position.","Keeping your torso forward and stationary, and the arms slightly bent at the elbows, lift the dumbbells straight to the side until both arms are parallel to the floor. Exhale as you lift the weights. (Note: avoid swinging the torso or bringing the arms back as opposed to the side.)","After a one second contraction at the top, slowly lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Seated_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension",name:"Seated Bent-Over Two-Arm Dumbbell Triceps Extension",instructions:["Sit down at the end of a flat bench with a dumbbell in both arms using a neutral grip (palms of the hand facing you).","Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.","The upper arms with the dumbbells should be close to the torso and aligned with it (lifted up until they are parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights). Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.","Keeping the upper arms stationary, use the triceps to lift the weight as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.","After a second contraction at the top, slowly lower the dumbbells back to the starting position as you inhale.","Repeat the movement for the prescribed amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Seated_Biceps",name:"Seated Biceps",instructions:["Sit on the floor with your knees bent and your partner standing behind you. Extend your arms straight behind you with your palms facing each other. Your partner will hold your wrists for you. This will be the starting position.","Attempt to flex your elbows, while your partner prevents any actual movement.","After 10-20 seconds, relax your arms while your partner gently pulls your wrists up to stretch your biceps. Be sure to let your partner know when the stretch is appropriate to prevent injury or overstretching."],muscleGroups:["arms"],equipment:[],level:"advanced",category:"stretching",tags:["force:static","mechanic:isolation","secondary:upper_body"]},{id:"Seated_Calf_Stretch",name:"Seated Calf Stretch",instructions:["Sit up straight on an exercise mat.","Bend one knee and put that foot on the floor to stabilize the torso.","Straighten your other leg and flex your ankle.","Using a band, towel, or your hand if you can reach, pull the toes toward you. Hold for 10 to 20 seconds, then switch sides."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:legs","secondary:back_posture"]},{id:"Seated_Dumbbell_Curl",name:"Seated Dumbbell Curl",instructions:["Sit on a flat bench with a dumbbell on each hand being held at arms length. The elbows should be close to the torso.","Rotate the palms of the hands so that they are facing your torso. This will be your starting position.","While holding the upper arm stationary, curl the weights and start twisting the wrists once the dumbbells pass your thighs so that the palms of your hands face forward at the end of the movement. Make sure that you contract the biceps as you breathe out and make sure that only the forearms move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in and as you rotate the wrists back to a neutral grip.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Seated_Dumbbell_Inner_Biceps_Curl",name:"Seated Dumbbell Inner Biceps Curl",instructions:["Sit on the end of a flat bench with a dumbbell in each hand being held at arms length. The elbows should be close to the torso.","Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.","While holding the upper arms stationary, curl the dumbbells out and up, turning the palms out as you lift and keeping your forearms in line with your outer deltoids. Tips:","Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate your arms as you lower the dumbbells so that you can switch back to a neutral grip.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Seated_Dumbbell_Palms-Down_Wrist_Curl",name:"Seated Dumbbell Palms-Down Wrist Curl",instructions:["Start out by placing two dumbbells on the floor in front of a flat bench.","Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.","Use your arms to grab both of the dumbbells and bring them up so that your forearms are resting against your thighs with the palms of the hands facing down. Your wrists should be hanging over the edge of your thighs.","Start out by curling your wrist upwards and exhaling.","Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Tip: Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.","Repeat for the recommended amount of repetitions.","When finished, simply lower the dumbbells to the floor."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Seated_Dumbbell_Palms-Up_Wrist_Curl",name:"Seated Dumbbell Palms-Up Wrist Curl",instructions:["Start out by placing two dumbbells on the floor in front of a flat bench.","Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.","Use your arms to grab both of the dumbbells and bring them up so that your forearms are resting against your thighs with the palms of the hands facing up. Your wrists should be hanging over the edge of your thighs.","Start out by curling your wrist upwards and exhaling.","Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Tip: Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.","Repeat for the recommended amount of repetitions.","When finished, simply lower the dumbbells to the floor."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Seated_Dumbbell_Press",name:"Seated Dumbbell Press",instructions:["Grab a couple of dumbbells and sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs.","Clean the dumbbells up one at a time by using your thighs to bring the dumbbells up to shoulder height at each side.","Rotate the wrists so that the palms of your hands are facing forward. This is your starting position.","As you exhale, push the dumbbells up until they touch at the top.","After a second pause, slowly come down back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Seated_Flat_Bench_Leg_Pull-In",name:"Seated Flat Bench Leg Pull-In",instructions:["Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.","Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.","After a second pause, go back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Seated_Floor_Hamstring_Stretch",name:"Seated Floor Hamstring Stretch",instructions:["Sit on a mat with your right leg extended in front of you and your left leg bent with your foot against your right inner thigh.","Lean forward from your hips and reach for your ankle until you feel a stretch in your hamstring. Hold for 15 seconds, then repeat for your other side."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Seated_Front_Deltoid",name:"Seated Front Deltoid",instructions:["Sit upright on the floor with your legs bent, your partner standing behind you. Stick your arms straight out to your sides, with your palms facing the ground. Attempt to move them as far behind you as possible, as your assistant holds your wrists. This will be your starting position.","Keeping your elbows straight, attempt to move your arms to the front, with your partner gently restraining you to prevent any actual movement for 10-20 seconds.","Now, relax your muscles and allow your partner to gently increase the stretch on the shoulders and chest. Hold for 10 to 20 seconds."],muscleGroups:["upper_body"],equipment:[],level:"advanced",category:"stretching",tags:["force:static","secondary:upper_body"]},{id:"Seated_Glute",name:"Seated Glute",instructions:["In a seated position with your knees bent, cross one ankle over the opposite knee. Your partner will stand behind you. Now, lean forward as your partner braces your shoulders with their hands. This will be your starting position.","Attempt to push your torso back for 10-20 seconds, as your partner prevents any actual movement of your torso.","Now relax your muscles as your partner increases the stretch by gently pushing your torso forward for 10-20 seconds."],muscleGroups:["glutes"],equipment:[],level:"advanced",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Seated_Hamstring",name:"Seated Hamstring",instructions:["In a seated position with your legs extended, have your partner stand behind you. Now, lean forward as your partner braces your shoulders with their hands. This will be your starting position.","Attempt to push your torso back for 10-20 seconds, as your partner prevents any actual movement of your torso.","Now relax your muscles as your partner increases the stretch by gently pushing your torso forward for 10-20 seconds."],muscleGroups:["legs"],equipment:[],level:"advanced",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Seated_Leg_Tucks",name:"Seated Leg Tucks",instructions:["Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.","Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.","After a second pause, go back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Seated_One-Arm_Dumbbell_Palms-Down_Wrist_Curl",name:"Seated One-Arm Dumbbell Palms-Down Wrist Curl",instructions:["Sit on a flat bench with a dumbbell in your right hand.","Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.","Lean forward and place your right forearm on top of your upper right thigh with your palm down. Tip: Make sure that the back of the wrist lies on top of your knees. This will be your starting position.","Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.","Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.","Perform for the recommended amount of repetitions, switch arms and repeat the movement."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Seated_One-Arm_Dumbbell_Palms-Up_Wrist_Curl",name:"Seated One-Arm Dumbbell Palms-Up Wrist Curl",instructions:["Sit on a flat bench with a dumbbell in your right hand.","Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.","Lean forward and place your right forearm on top of your upper right thigh with your palm up. Tip: Make sure that the front of the wrist lies on top of your knees. This will be your starting position.","Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.","Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.","Perform for the recommended amount of repetitions, switch arms and repeat the movement."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Seated_Overhead_Stretch",name:"Seated Overhead Stretch",instructions:["Sit up straight on an exercise mat.","Touch the soles of your feet together with your feet six to eight inches in front of your hips.","Place one hand on the floor beside you and your other hand behind your head.","Lift your elbow to the ceiling as you incline your torso to the other side. Hold for 10 to 20 seconds, then switch sides."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Seated_Side_Lateral_Raise",name:"Seated Side Lateral Raise",instructions:["Pick a couple of dumbbells and sit at the end of a flat bench with your feet firmly on the floor. Hold the dumbbells with your palms facing in and your arms straight down at your sides at arms' length. This will be your starting position.","While maintaining the torso stationary (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.","Lower the dumbbells back down slowly to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Seated_Triceps_Press",name:"Seated Triceps Press",instructions:["Sit down on a bench with back support and grasp a dumbbell with both hands and hold it overhead at arm's length. Tip: a better way is to have somebody hand it to you especially if it is very heavy. The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hand should be facing inward. This will be your starting position.","Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semi-circular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.","Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"See-Saw_Press_Alternating_Side_Press",name:"See-Saw Press (Alternating Side Press)",instructions:["Grab a dumbbell with each hand and stand up erect.","Clean (lift) the dumbbells to the chest/shoulder level and then rotate your wrists so that your palms are facing towards you as if you were getting ready to perform an Arnold Press. This will be your starting position.","Now start extending your left arm overhead as you rotate the wrist so that the palm of your hand faces forward as you go up. Your elbows should come out also as you lift the weight. Simultaneously, you will also be bending from your hip to your opposite side. Tip: If you perform the exercise correctly, is should look as if you are trying to reach for something overhead on the right hand side of your body, but with your left arm. Breathe out as you perform this movement.","Once you reach the top position breathe in. Then, with the weight fully extended overhead and you bent over to your right hand side, begin the movement to the left side.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:core_abs","secondary:arms"]},{id:"Shoulder_Circles",name:"Shoulder Circles",instructions:["With shoulders relaxed and arms resting loosely at your sides (or in your lap if you're seated), gently roll your shoulders forward, up, back, and down.","Reverse direction. You can do this exercise alternating shoulders or both at the same time."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","secondary:upper_body"]},{id:"Shoulder_Press_-_With_Bands",name:"Shoulder Press - With Bands",instructions:["To begin, stand on an exercise band so that tension begins at arm's length. Grasp the handles and lift them so that the hands are at shoulder height at each side.","Rotate the wrists so that the palms of your hands are facing forward. Your elbows should be bent, with the upper arms and forearms in line to the torso. This is your starting position.","As you exhale, lift the handles up until your arms are fully extended overhead."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Shoulder_Raise",name:"Shoulder Raise",instructions:["Relax your arms to your sides and raise your shoulders up toward your ears, then back down."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","secondary:back_posture"]},{id:"Shoulder_Stretch",name:"Shoulder Stretch",instructions:["Reach your left arm across your body and hold it straight."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull"]},{id:"Side_Lateral_Raise",name:"Side Lateral Raise",instructions:["Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position.","While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.","Lower the dumbbells back down slowly to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Side_Laterals_to_Front_Raise",name:"Side Laterals to Front Raise",instructions:["In a standing position, hold a pair of dumbbells at your side. This will be your starting position.","Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.","At the top of the exercise move the weights out in front of you, keeping your arms extended.","Lower the weights with a controlled motion.","On the next repetition, raise the weights in front of you to shoulder height before moving the weights laterally to your sides.","Lower the weights to the starting position."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation","secondary:upper_body"]},{id:"Side_Leg_Raises",name:"Side Leg Raises",instructions:["Stand next to a chair, which you may hold onto as a support. Stand on one leg. This will be your starting position.","Keeping your leg straight, raise it as far out to the side as possible, and swing it back down, allowing it to cross the opposite leg.","Repeat this swinging motion 5-10 times, increasing the range of motion as you do so."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull"]},{id:"Side_Lying_Groin_Stretch",name:"Side Lying Groin Stretch",instructions:["Start off by lying on your right side and bend your right knee in front of you to stabilize the torso.","Rest your head on your right hand or shoulder. Lift your left leg upward and hold it by the back of the knee (easier) or the foot (harder).","Pull your left knee in toward your left shoulder and simultaneously press your foot or knee down to the floor. To intensify this stretch, straighten your left leg. Switch sides."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:legs"]},{id:"Side_Neck_Stretch",name:"Side Neck Stretch",instructions:["Start with your shoulders relaxed, gently tilt your head towards your shoulder.","Assist stretch with a gentle pull on the side of the head."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Side_Standing_Long_Jump",name:"Side Standing Long Jump",instructions:["Begin standing with your feet hip width apart in an athletic stance. Your head and chest should be up, knees and hips slightly bent. This will be your starting position.","Leaning to your right, extend through your hips, knees, and ankles to jump into the air. Block with the arms to lead the movement, jumping as far to your right as you can.","Land facing the same direction with your feet hip width apart, absorbing the impact through your lower body."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Side_Wrist_Pull",name:"Side Wrist Pull",instructions:["This stretch works best standing. Cross your left arm over the midline of your body and hold the left wrist in your right hand down at the level of your hips. Start the stretch with a bent left arm.","Slowly straighten, pull, and lift it up to shoulder height, as pictured. Feel this stretch originate in your back, not your shoulders, and don't pull too hard on the shoulders joint. Switch sides."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:arms","secondary:back_posture"]},{id:"Side-Lying_Floor_Stretch",name:"Side-Lying Floor Stretch",instructions:["First lie on your left side, bending your left knee in front of you to stabilize your torso (use your abdominal muscles as well to hold you upright).","Straighten your right leg and rest the right foot on the floor behind your left. Straighten your right arm over your head and gently pull on your right wrist to stretch the entire right side of the body. Switch sides."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static"]},{id:"Single_Dumbbell_Raise",name:"Single Dumbbell Raise",instructions:["With a wide stance, hold a dumbell with both hands, grasping the head of the dumbbell instead of the handle. Your arms should be extended and hanging at the waist. This will be your starting position.","Raise the weight until it is above shoulder level, keeping your arms extended. Your torso and hips should remain stationary throughout the movement.","Return to the starting position and repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["mechanic:isolation","secondary:arms","secondary:upper_body"]},{id:"Single_Leg_Butt_Kick",name:"Single Leg Butt Kick",instructions:["Begin by standing on one leg, with the bent knee raised. This will be your start position.","Using a countermovement jump, take off upward by extending the hip, knee, and ankle of the grounded leg.","Immediately flex the knee and attempt to touch your butt with the heel of your jumping leg.","Return the leg to a partially bent position underneath the hips and land. Your opposite leg should stay in relatively the same position throughout the drill."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs"]},{id:"Single_Leg_Glute_Bridge",name:"Single Leg Glute Bridge",instructions:["Lay on the floor with your feet flat and knees bent.","Raise one leg off of the ground, pulling the knee to your chest. This will be your starting position.","Execute the movement by driving through the heel, extending your hip upward and raising your glutes off of the ground.","Extend as far as possible, pause and then return to the starting position."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation","secondary:legs"]},{id:"Single-Arm_Push-Up",name:"Single-Arm Push-Up",instructions:["Begin laying prone on the ground. Move yourself into a position supporting your weight on your toes and one arm. Your working arm should be placed directly under the shoulder, fully extended. Your legs should be extended, and for this movement you may need a wider base, placing your feet further apart than in a normal push-up.","Maintain good posture, and place your free hand behind your back. This will be your starting position.","Lower yourself by allowing the elbow to flex until you touch the ground.","Descend slowly, and reverse direction be extending the arm to return to the starting position."],muscleGroups:["upper_body"],equipment:[],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Sit_Squats",name:"Sit Squats",instructions:["Stand with your feet shoulder width apart. This will be your starting position.","Begin the movement by flexing your knees and hips, sitting back with your hips.","Continue until you have squatted a portion of the way down, but are above parallel, and quickly reverse the motion until you return to the starting position. Repeat for 5-10 repetitions."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:push","secondary:legs","secondary:glutes"]},{id:"Sit-Up",name:"Sit-Up",instructions:["Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.","Place your hands behind your head and lock them together by clasping your fingers. This is the starting position.","Elevate your upper body so that it creates an imaginary V-shape with your thighs. Breathe out when performing this part of the exercise.","Once you feel the contraction for a second, lower your upper body back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Speed_Band_Overhead_Triceps",name:"Speed Band Overhead Triceps",instructions:["For this exercise anchor a band to the ground. We used an incline bench and anchored the band to the base, standing over the bench. Alternatively, this could be performed standing on the band.","To begin, pull the band behind your head, holding it with a pronated grip and your elbows up. This will be your starting position.","To perform the movement, extend through the elbow to to straighten your arms, ensuring that you keep your upper arm in place.","Pause, and then return to the starting position."],muscleGroups:["arms"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Spell_Caster",name:"Spell Caster",instructions:["Hold a dumbbell in each hand with a pronated grip. Your feet should be wide with your hips and knees extended. This will be your starting position.","Begin the movement by pulling both of the dumbbells to one side next to your hip, rotating your torso.","Keeping your arms straight and the dumbbells parallel to the ground, rotate your torso to swing the weights to your opposite side.","Continue alternating, rotating from one side to the other until the set is complete."],muscleGroups:["core_abs"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:glutes","secondary:upper_body"]},{id:"Spider_Crawl",name:"Spider Crawl",instructions:["Begin in a prone position on the floor. Support your weight on your hands and toes, with your feet together and your body straight. Your arms should be bent to 90 degrees. This will be your starting position.","Initiate the movement by raising one foot off of the ground. Externally rotate the leg and bring the knee toward your elbow, as far forward as possible.","Return this leg to the starting position and repeat on the opposite side."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:upper_body","secondary:arms"]},{id:"Spinal_Stretch",name:"Spinal Stretch",instructions:["Sit in a chair so your back is straight and your feet planted on the floor.","Interlace your fingers behind your head, elbows out and your chin down.","Twist your upper body to one side about 3 times as far as you can. Then lean forward and twist your torso to reach your elbow to the floor on the inside of your knee.","Return to upright position and then repeat for your other side."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:back_posture","secondary:upper_body"]},{id:"Split_Jump",name:"Split Jump",instructions:["Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.","Ensure that the front knee is over the midline of the foot.","Extending through both legs, jump as high as possible, swinging your arms to gain lift.","As you jump, bring your feet together, and move them back to their initial positions as you land.","Absorb the impact by reverting back to the starting position."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Split_Squat_with_Dumbbells",name:"Split Squat with Dumbbells",instructions:["Position yourself into a staggered stance with the rear foot elevated and front foot forward.","Hold a dumbbell in each hand, letting them hang at the sides. This will be your starting position.","Begin by descending, flexing your knee and hip to lower your body down. Maintain good posture througout the movement. Keep the front knee in line with the foot as you perform the exercise.","At the bottom of the movement, drive through the heel to extend the knee and hip to return to the starting position."],muscleGroups:["legs"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:glutes","secondary:legs"]},{id:"Split_Squats",name:"Split Squats",instructions:["Being in a standing position. Jump into a split leg position, with one leg forward and one leg back, flexing the knees and lowering your hips slightly as you do so.","As you descend, immediately reverse direction, standing back up and jumping, reversing the position of your legs. Repeat 5-10 times on each leg."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:push","secondary:legs","secondary:glutes"]},{id:"Squats_-_With_Bands",name:"Squats - With Bands",instructions:["To start out, make sure that the exercise band is at an even split between both the left and right side of the body. To do this, use your hands to grab both sides of the band and place both feet in the middle of the band. Your feet should be shoulder width apart from each other.","When holding the bands, they should be the same height on each side. You should be using a pronated grip (palms facing forward) and have the handles of the bands next to your face for this exercise. This is the starting position.","Slowly start to bend the knees and lower the legs so that your thighs are parallel to the floor while exhaling.","Use the heel of your feet to push your body up to the starting position as you exhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes","secondary:back_posture"]},{id:"Standing_Alternating_Dumbbell_Press",name:"Standing Alternating Dumbbell Press",instructions:["Stand with a dumbbell in each hand. Raise the dumbbells to your shoulders with your palms facing forward and your elbows pointed out. This will be your starting position.","Extend one arm to press the dumbbell straight up, keeping your off hand in place. Do not lean or jerk the weight during the movement.","After a brief pause, return the weight to the starting position.","Repeat for the opposite side, continuing to alternate between arms."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Standing_Bent-Over_One-Arm_Dumbbell_Triceps_Extension",name:"Standing Bent-Over One-Arm Dumbbell Triceps Extension",instructions:["With a dumbbell in one hand and the palm facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.","The upper arm should be close to the torso and parallel to the floor while the forearm is pointing towards the floor as the hand holds the weight. Tip: There should be a 90-degree angle between the forearm and the upper arm. This is your starting position.","Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.","After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale.","Repeat the movement for the prescribed amount of repetitions.","Switch arms and repeat the exercise."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation","secondary:upper_body"]},{id:"Standing_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension",name:"Standing Bent-Over Two-Arm Dumbbell Triceps Extension",instructions:["With a dumbbell in each hand and the palms facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up. The upper arms should be close to the torso and parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights. Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.","Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arms are extended. Like many other arm exercises, only the forearm moves.","After a second contraction at the top, slowly lower the dumbbells back to their starting position as you inhale.","Repeat the movement for the prescribed amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Standing_Concentration_Curl",name:"Standing Concentration Curl",instructions:["Taking a dumbbell in your working hand, lean forward. Allow your working arm to hang perpendicular to the ground with the elbow pointing out. This will be your starting position.","Flex the elbow to curl the weight, keeping the upper arm stationary. At the top of the repetition, flex the biceps and pause.","Lower the dumbbell back to the starting position.","Repeat the movement for the prescribed amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Standing_Dumbbell_Calf_Raise",name:"Standing Dumbbell Calf Raise",instructions:["Stand with your torso upright holding two dumbbells in your hands by your sides. Place the ball of the foot on a sturdy and stable wooden board (that is around 2-3 inches tall) while your heels extend off and touch the floor. This will be your starting position.","With the toes pointing either straight (to hit all parts equally), inwards (for emphasis on the outer head) or outwards (for emphasis on the inner head), raise the heels off the floor as you exhale by contracting the calves. Hold the top contraction for a second.","As you inhale, go back to the starting position by slowly lowering the heels.","Repeat for the recommended amount of times."],muscleGroups:["legs"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Standing_Dumbbell_Press",name:"Standing Dumbbell Press",instructions:["Standing with your feet shoulder width apart, take a dumbbell in each hand. Raise the dumbbells to head height, the elbows out and about 90 degrees. This will be your starting position.","Maintaining strict technique with no leg drive or leaning back, extend through the elbow to raise the weights together directly above your head.","Pause, and slowly return the weight to the starting position."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Standing_Dumbbell_Reverse_Curl",name:"Standing Dumbbell Reverse Curl",instructions:["To begin, stand straight with a dumbbell in each hand using a pronated grip (palms facing down). Your arms should be fully extended while your feet are shoulder width apart from each other. This is the starting position.","While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the muscle.","Slowly begin to bring the dumbbells back to starting position as your breathe in.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Standing_Dumbbell_Straight-Arm_Front_Delt_Raise_Above_Head",name:"Standing Dumbbell Straight-Arm Front Delt Raise Above Head",instructions:["Hold the dumbbells in front of your thighs, palms facing your thighs.","Keep your arms straight with a slight bend at the elbows but keep them locked. This will be your starting position.","Raise the dumbbells in a semicircular motion to arm's length overhead as you exhale.","Slowly return to the starting position using the same path as you inhale.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Standing_Dumbbell_Triceps_Extension",name:"Standing Dumbbell Triceps Extension",instructions:["To begin, stand up with a dumbbell held by both hands. Your feet should be about shoulder width apart from each other. Slowly use both hands to grab the dumbbell and lift it over your head until both arms are fully extended.","The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hands should be facing up towards the ceiling. This will be your starting position.","Keeping your upper arms close to your head with elbows in and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.","Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Standing_Dumbbell_Upright_Row",name:"Standing Dumbbell Upright Row",instructions:["Grasp a dumbbell in each hand with a pronated (palms forward) grip that is slightly less than shoulder width. The dumbbells should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.","Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be close to the body as you move it up and the elbows should drive the motion. Continue to lift them until they nearly touch your chin. Tip: Your elbows should drive the motion. As you lift the dumbbells, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the dumbbells back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:upper_body"]},{id:"Standing_Gastrocnemius_Calf_Stretch",name:"Standing Gastrocnemius Calf Stretch",instructions:["Place your right heel on a step with your knee extended and lean forward to grab your right toe with your right hand. Your left knee should be slightly bent and your back should be straight.","Support your weight on your left leg and place your left hand on your left thigh.","Pull your right toes toward your knee until you feel a stretch in your calf."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Standing_Hip_Circles",name:"Standing Hip Circles",instructions:["Begin standing on one leg, holding to a vertical support.","Raise the unsupported knee to 90 degrees. This will be your starting position.","Open the hip as far as possible, attempting to make a big circle with your knee.","Perform this movement slowly for a number of repetitions, and repeat on the other side."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","mechanic:isolation","secondary:legs"]},{id:"Standing_Hip_Flexors",name:"Standing Hip Flexors",instructions:["Stand up straight with the spine vertical, the left foot slightly in front of the right.","Bend both knees and lift the back heel off the floor as you press the right hip forward. You can't get a thorough, deep stretch in this position, however, because it's hard to relax the hip flexor and stand on it at the same time. Switch sides."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Standing_Inner-Biceps_Curl",name:"Standing Inner-Biceps Curl",instructions:["Stand up with a dumbbell in each hand being held at arms length. The elbows should be close to the torso. Your legs should be at about shoulder's width apart from each other.","Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.","While holding the upper arms stationary, curl the weights out while contracting the biceps as you breathe out. Your wrist should turn so that when the weights are fully elevated you have supinated grip (palms facing up).","Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: Keep the forearms aligned with your outer deltoids.","Hold the contracted position for a second as you squeeze the biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate the wrists as you lower the weight in order to switch back to a neutral grip.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Standing_Lateral_Stretch",name:"Standing Lateral Stretch",instructions:["Take a slightly wider than hip distance stance with your knees slightly bent.","Place your right hand on your right hip to support the spine.","Raise your left arm in a vertical line and place your left hand behind your head. Keep it there as you incline your torso to the right.","Keep your weight evenly distributed between both legs (don't lean into your left hip). Switch sides."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static"]},{id:"Standing_Long_Jump",name:"Standing Long Jump",instructions:["This drill is best done in sand or other soft landing surface. Ensure that you are able to measure distance. Stand in a partial squat stance with feet shoulder width apart.","Utilizing a big arm swing and a countermovement of the legs, jump forward as far as you can.","Attempt to land with your feet out in front you, reaching as far as possible with your legs.","Measure the distance from your landing point to the starting point and track results."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes"]},{id:"Standing_One-Arm_Dumbbell_Curl_Over_Incline_Bench",name:"Standing One-Arm Dumbbell Curl Over Incline Bench",instructions:["Stand on the back side of an incline bench as if you were going to be a spotter for someone. Have a dumbbell in one hand and rest it across the incline bench with a supinated (palms up) grip.","Position your non lifting hand at the corner or side of the incline bench. The chest should be pressed against the top part of the incline and your feet should be pressed against the floor at a wide stance. This is the starting position.","While holding the upper arm stationary, curl the dumbbell upward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a second.","Slowly begin to bring the dumbbells back to starting position as your breathe in.","Repeat for the recommended amount of repetitions.","Switch arms while performing this exercise."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Standing_One-Arm_Dumbbell_Triceps_Extension",name:"Standing One-Arm Dumbbell Triceps Extension",instructions:["To begin, stand up with a dumbbell held in one hand. Your feet should be about shoulder width apart from each other. Now fully extend the arm with the dumbbell over your head. Tip: The small finger of your hand should be facing the ceiling and the palm of your hand should be facing forward. The dumbbell should be above your head.","This will be your starting position.","Keeping your upper arm close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearm touch your bicep. Tip: The upper arm should remain stationary and only the forearm should move. Breathe in as you perform this step.","Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.","Repeat for the recommended amount of repetitions.","Switch arms and repeat the exercise."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation","secondary:upper_body"]},{id:"Standing_Palm-In_One-Arm_Dumbbell_Press",name:"Standing Palm-In One-Arm Dumbbell Press",instructions:["Start by having a dumbbell in one hand with your arm fully extended to the side using a neutral grip. Use your other arm to hold on to an incline bench to keep your balance.","Your feet should be shoulder width apart from each other. Now slowly lift the dumbbell up until you create a 90 degree angle with your arm. Note: Your forearm should be perpendicular to the floor. Continue to maintain a neutral grip throughout the entire exercise.","Slowly lift the dumbbell up until your arm is fully extended. This the starting position.","While inhaling lower the weight down until your arm is at a 90 degree angle again.","Feel the contraction for a second and then lift the weight back up towards the starting position while exhaling. Remember to hold on to the incline bench and keep your feet positioned to keep balance during the exercise.","Repeat for the recommended amount of repetitions.","Switch arms and repeat the exercise."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Standing_Palms-In_Dumbbell_Press",name:"Standing Palms-In Dumbbell Press",instructions:["Start by having a dumbbell in each hand with your arm fully extended to the side using a neutral grip. Your feet should be shoulder width apart from each other. Now slowly lift the dumbbells up until you create a 90 degree angle with your arms. Note: Your forearms should be perpendicular to the floor. This the starting position.","Continue to maintain a neutral grip throughout the entire exercise. Slowly lift the dumbbells up until your arms are fully extended.","While inhaling lower the weights down until your arm is at a 90 degree angle again.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:compound","secondary:arms"]},{id:"Standing_Pelvic_Tilt",name:"Standing Pelvic Tilt",instructions:["Start off with your feet hip-distance apart.","Bend your knees slightly to keep them soft and springy.","You may want to move your pelvis forward and backward and back few times before holding the tailbone forward in this stretch."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:glutes"]},{id:"Standing_Soleus_And_Achilles_Stretch",name:"Standing Soleus And Achilles Stretch",instructions:["Stand with your feet hip-distance apart, one foot slightly in front of the other.","Bend both knees, keeping your back heel on the floor. Switch sides."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Standing_Toe_Touches",name:"Standing Toe Touches",instructions:["Stand with some space in front and behind you.","Bend at the waist, keeping your legs straight, until you can relax and let your upper body hang down in front of you. Let your arms and hands hang down naturally. Hold for 10 to 20 seconds."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Standing_Towel_Triceps_Extension",name:"Standing Towel Triceps Extension",instructions:["To begin, stand up with both arms fully extended above the head holding one end of a towel with both hands. Your elbows should be in and the arms perpendicular to the floor with the palms facing each other while your feet should be shoulder width apart from each other. This is the starting position.","Now communicate with your partner so that he/she can grip the other side of the towel to apply resistance. Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.","Go back to the starting position by using the triceps to raise the towel. Breathe out as you perform this step.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Standing_Two-Arm_Overhead_Throw",name:"Standing Two-Arm Overhead Throw",instructions:["Stand with your feet shoulder width apart holding a medicine ball in both hands. To begin, reach the medicine ball deep behind your head as you bend the knees slightly and lean back.","Violently throw the ball forward, flexing at the hip and using your whole body to complete the movement.","The medicine ball can be thrown to a partner or to a wall, receiving it as it bounces back."],muscleGroups:["upper_body"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:pull","mechanic:compound","secondary:upper_body","secondary:back_posture"]},{id:"Star_Jump",name:"Star Jump",instructions:["Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.","To initiate the move, squat down halfway and explode back up as high as possible. Fully extend your entire body, spreading your legs and arms away from the body.","As you land, bring your limbs back in and absorb your impact through the legs."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:legs","secondary:glutes","secondary:upper_body"]},{id:"Step-up_with_Knee_Raise",name:"Step-up with Knee Raise",instructions:["Stand facing a box or bench of an appropriate height with your feet together. This will be your starting position.","Begin the movement by stepping up, putting your left foot on the top of the bench. Extend through the hip and knee of your front leg to stand up on the box. As you stand on the box with your left leg, flex your right knee and hip, bringing your knee as high as you can.","Reverse this motion to step down off the box, and then repeat the sequence on the opposite leg."],muscleGroups:["glutes"],equipment:[],level:"beginner",category:"strength",tags:["force:push","mechanic:compound","secondary:legs"]},{id:"Stiff-Legged_Dumbbell_Deadlift",name:"Stiff-Legged Dumbbell Deadlift",instructions:["Grasp a couple of dumbbells holding them by your side at arm's length.","Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.","Keeping the knees stationary, lower the dumbbells to over the top of your feet by bending at the waist while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Exhale as you perform this movement","Start bringing your torso up straight again by extending your hips and waist until you are back at the starting position. Inhale as you perform this movement.","Repeat for the recommended amount of repetitions."],muscleGroups:["legs"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:glutes","secondary:back_posture"]},{id:"Stomach_Vacuum",name:"Stomach Vacuum",instructions:["To begin, stand straight with your feet shoulder width apart from each other. Place your hands on your hips. This is the starting position.","Now slowly inhale as much air as possible and then start to exhale as much as possible while bringing your stomach in as much as possible and hold this position. Try to visualize your navel touching your backbone.","One isometric contraction is around 20 seconds. During the 20 second hold, try to breathe normally. Then inhale and bring your stomach back to the starting position.","Once you have practiced this exercise, try to perform this exercise for longer than 20 seconds. Tip: You can work your way up to 40-60 seconds.","Repeat for the recommended amount of sets."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation"]},{id:"Straight-Arm_Dumbbell_Pullover",name:"Straight-Arm Dumbbell Pullover",instructions:["Place a dumbbell standing up on a flat bench.","Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.","Grasp the dumbbell with both hands and hold it straight over your chest at arms length. Both palms should be pressing against the underside one of the sides of the dumbbell. This will be your starting position.\nCaution: Always ensure that the dumbbell used for this exercise is secure. Using a dumbbell with loose plates can result in the dumbbell falling apart and falling on your face.","While keeping your arms straight, lower the weight slowly in an arc behind your head while breathing in until you feel a stretch on the chest.","At that point, bring the dumbbell back to the starting position using the arc through which the weight was lowered and exhale as you perform this movement.","Hold the weight on the initial position for a second and repeat the motion for the prescribed number of repetitions."],muscleGroups:["upper_body"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:back_posture","secondary:upper_body","secondary:arms"]},{id:"Superman",name:"Superman",instructions:["To begin, lie straight and face down on the floor or exercise mat. Your arms should be fully extended in front of you. This is the starting position.","Simultaneously raise your arms, legs, and chest off of the floor and hold this contraction for 2 seconds. Tip: Squeeze your lower back to get the best results from this exercise. Remember to exhale during this movement. Note: When holding the contracted position, you should look like superman when he is flying.","Slowly begin to lower your arms, legs and chest back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions prescribed in your program."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:compound","secondary:glutes","secondary:legs"]},{id:"Supine_Chest_Throw",name:"Supine Chest Throw",instructions:["This drill is great for chest passes when you lack a partner or a wall of sufficient strength. Lay on the ground on your back with your knees bent.","Begin with the ball on your chest, held with both hands on the bottom.","Explode up, extending through the elbow to throw the ball directly above you as high as possible.","Catch the ball with both hands as it comes down."],muscleGroups:["arms"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:push","mechanic:compound","secondary:upper_body"]},{id:"Supine_One-Arm_Overhead_Throw",name:"Supine One-Arm Overhead Throw",instructions:["Lay on the ground on your back with your knees bent. Hold the ball with one hand, extending the arm fully behind your head. This will be your starting position.","Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.","The ball can be thrown to a partner or bounced off of a wall."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:pull","mechanic:compound","secondary:upper_body","secondary:back_posture"]},{id:"Supine_Two-Arm_Overhead_Throw",name:"Supine Two-Arm Overhead Throw",instructions:["Lay on the ground on your back with your knees bent.","Hold the ball with both hands, extending the arms fully behind your head. This will be your starting position.","Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.","The ball can be thrown to a partner or bounced off of a wall."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"beginner",category:"plyometrics",tags:["force:pull","mechanic:compound","secondary:upper_body","secondary:back_posture"]},{id:"Tate_Press",name:"Tate Press",instructions:["Lie down on a flat bench with a dumbbell in each hand on top of your thighs. The palms of your hand will be facing each other.","By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them in front of you at shoulder width. Note: when holding the dumbbells in front of you, make sure your arms are wider than shoulder width apart from each other using a pronated (palms forward) grip. Allow your elbows to point out. This is your starting position.","Keeping the upper arms stationary, slowly move the dumbbells in and down in a semi circular motion until they touch the upper chest while inhaling. Keep full control of the dumbbells at all times and do not move the upper arms nor rest the dumbbells on the chest.","As you breathe out, move the dumbbells up using your triceps and the same semi-circular motion but in reverse. Attempt to keep the dumbbells together as they move up. Lock your arms in the contracted position, hold for a second and then start coming down again slowly again. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions of your training program."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:push","mechanic:isolation","secondary:upper_body"]},{id:"The_Straddle",name:"The Straddle",instructions:["Begin in a seated, upright position. Start by extending your legs in front of you in a V.","With your hands on the floor, lean forward as far as possible. Hold for 10 to 20 seconds."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:legs"]},{id:"Toe_Touchers",name:"Toe Touchers",instructions:["To begin, lie down on the floor or an exercise mat with your back pressed against the floor. Your arms should be lying across your sides with the palms facing down.","Your legs should be touching each other. Slowly elevate your legs up in the air until they are almost perpendicular to the floor with a slight bend at the knees. Your feet should be parallel to the floor.","Move your arms so that they are fully extended at a 45 degree angle from the floor. This is the starting position.","While keeping your lower back pressed against the floor, slowly lift your torso and use your hands to try and touch your toes. Remember to exhale while perform this part of the exercise.","Slowly begin to lower your torso and arms back down to the starting position while inhaling. Remember to keep your arms straight out pointing towards your toes.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","mechanic:isolation"]},{id:"Torso_Rotation",name:"Torso Rotation",instructions:["Stand upright holding an exercise ball with both hands. Extend your arms so the ball is straight out in front of you. This will be your starting position.","Rotate your torso to one side, keeping your eyes on the ball as you move. Now, rotate back to the opposite direction. Repeat for 10-20 repetitions."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"beginner",category:"stretching",tags:["force:pull"]},{id:"Trail_Running_Walking",name:"Trail Running/Walking",instructions:["Running or hiking on trails will get the blood pumping and heart beating almost immediately. Make sure you have good shoes. While you use the muscles in your calves and buttocks to pull yourself up a hill, the knees, joints and ankles absorb the bulk of the pounding coming back down. Take smaller steps as you walk downhill, keep your knees bent to reduce the impact and slow down to avoid falling.","A 150 lb person can burn over 200 calories for 30 minutes walking uphill, compared to 175 on a flat surface. If running the trail, a 150 lb person can burn well over 500 calories in 30 minutes."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"cardio",tags:["secondary:legs","secondary:glutes"]},{id:"Tricep_Dumbbell_Kickback",name:"Tricep Dumbbell Kickback",instructions:["Start with a dumbbell in each hand and your palms facing your torso. Keep your back straight with a slight bend in the knees and bend forward at the waist. Your torso should be almost parallel to the floor. Make sure to keep your head up. Your upper arms should be close to your torso and parallel to the floor. Your forearms should be pointed towards the floor as you hold the weights. There should be a 90-degree angle formed between your forearm and upper arm. This is your starting position.","Now, while keeping your upper arms stationary, exhale and use your triceps to lift the weights until the arm is fully extended. Focus on moving the forearm.","After a brief pause at the top contraction, inhale and slowly lower the dumbbells back down to the starting position.","Repeat the movement for the prescribed amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:push","mechanic:isolation"]},{id:"Tricep_Side_Stretch",name:"Tricep Side Stretch",instructions:["Bring right arm across your body and over your left shoulder, holding your elbow with your left hand, until you feel a stretch in your tricep. Then repeat for your other arm."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:upper_body"]},{id:"Triceps_Stretch",name:"Triceps Stretch",instructions:["Reach your hand behind your head, grasp your elbow and gently pull. Hold for 10 to 20 seconds, then switch sides."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","mechanic:isolation","secondary:back_posture"]},{id:"Tuck_Crunch",name:"Tuck Crunch",instructions:["To begin, lie down on the floor or an exercise mat with your back pressed against the floor. Your arms should be lying across your sides with the palms facing down.","Your legs should be crossed by wrapping one ankle around the other. Slowly elevate your legs up in the air until your thighs are perpendicular to the floor with a slight bend at the knees. Note: Your knees and toes should be parallel to the floor as opposed to the thighs.","Move your arms from the floor and cross them so they are resting on your chest. This is the starting position.","While keeping your lower back pressed against the floor, slowly lift your torso. Remember to exhale while perform this part of the exercise.","Slowly begin to lower your torso back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Two-Arm_Dumbbell_Preacher_Curl",name:"Two-Arm Dumbbell Preacher Curl",instructions:["Grab a dumbbell with each arm and place the upper arms on top of the preacher bench or the incline bench. The dumbbell should be held at shoulder length. This will be your starting position.","As you breathe in, slowly lower the dumbbells until your upper arm is extended and the biceps is fully stretched.","As you exhale, use the biceps to curl the weights up until your biceps is fully contracted and the dumbbells are at shoulder height.","Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Upper_Back_Stretch",name:"Upper Back Stretch",instructions:["Clasp fingers together with your thumbs pointing down, round your shoulders as you reach your hands forward."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:back_posture"]},{id:"Upper_Back-Leg_Grab",name:"Upper Back-Leg Grab",instructions:["While seated, bend forward to hug your thighs from underneath with both arms.","Keep your knees together and your legs extended out as you bring your chest down to your knees. You can also stretch your middle back by pulling your back away from your knees as your hugging them."],muscleGroups:["legs"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:back_posture"]},{id:"Upright_Row_-_With_Bands",name:"Upright Row - With Bands",instructions:["To begin, stand on an exercise band so that tension begins at arm's length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.","Use your side shoulders to lift the handles as you exhale. The handles should be close to the body as you move them up. Continue to lift the handles until they nearly touches your chin. Tip: Your elbows should drive the motion. As you lift the handles, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the handles back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],muscleGroups:["upper_body"],equipment:["resistance_bands"],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:upper_body"]},{id:"Upward_Stretch",name:"Upward Stretch",instructions:["Extend both hands straight above your head, palms touching.","Slowly push your hands up and back, keeping your back straight."],muscleGroups:["upper_body"],equipment:[],level:"beginner",category:"stretching",tags:["force:static","secondary:upper_body","secondary:back_posture"]},{id:"V-Bar_Pullup",name:"V-Bar Pullup",instructions:["Start by placing the middle of the V-bar in the middle of the pull-up bar (assuming that the pull-up station you are using does not have neutral grip handles). The V-Bar handles will be facing down so that you can hang from the pull-up bar through the use of the handles.","Once you securely place the V-bar, take a hold of the bar from each side and hang from it. Stick your chest out and lean yourself back slightly in order to better engage the lats. This will be your starting position.","Using your lats, pull your torso up while leaning your head back slightly so that you do not hit yourself with the chin-up bar. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion.","After a second hold on the contracted position, slowly lower your body back to the starting position as you breathe in.","Repeat for the prescribed number of repetitions."],muscleGroups:["back_posture"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture","secondary:upper_body"]},{id:"Vertical_Swing",name:"Vertical Swing",instructions:["Allow the dumbbell to hang at arms length between your legs, holding it with both hands. Keep your back straight and your head up.","Swing the dumbbell between your legs, flexing at the hips and bending the knees slightly.","Powerfully reverse the motion by extending at the hips, knees, and ankles to propel yourself upward, swinging the dumbell over your head.","As you land, absorb the impact through your legs and draw the dumbbell to your torso before the next repetition."],muscleGroups:["legs"],equipment:["dumbbells"],level:"beginner",category:"plyometrics",tags:["force:pull","mechanic:compound","secondary:glutes","secondary:legs","secondary:upper_body"]},{id:"Weighted_Ball_Hyperextension",name:"Weighted Ball Hyperextension",instructions:["To begin, lie down on an exercise ball with your torso pressing against the ball and parallel to the floor. The ball of your feet should be pressed against the floor to help keep you balanced. Place a weighted plate under your chin or behind your neck. This is the starting position.","Slowly raise your torso up by bending at the waist and lower back. Remember to exhale during this movement.","Hold the contraction on your lower back for a second and lower your torso back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions prescribed in your program."],muscleGroups:["back_posture"],equipment:["pilates_equipment"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:glutes","secondary:legs","secondary:back_posture"]},{id:"Weighted_Ball_Side_Bend",name:"Weighted Ball Side Bend",instructions:["To begin, lie down on an exercise ball with your left side of the torso (waist, hips and shoulder) pressed against the ball.","Your feet should be on the floor while your legs are crossed and hanging from the ball. Hold a weighted plate with your right hand directly to the right side of your head. Tip: Make sure the smooth side of the plate is resting against your head.","Place your left arm across your torso so that your palm is on your obliques. There should be a right angle between your left forearm and upper arm. This is the starting position.","Raise the side of your torso up by laterally flexing at the waist while exhaling.","Hold the contraction for a second and slowly lower yourself back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions.","Switch sides and repeat the exercise."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Weighted_Crunches",name:"Weighted Crunches",instructions:["Lie flat on your back with your feet flat on the ground or resting on a bench with your knees bent at a 90 degree angle.","Hold a weight to your chest, or you may hold it extended above your torso. This will be your starting position.","Now, exhale and slowly begin to roll your shoulders off the floor. Your shoulders should come up off the floor about 4 inches while your lower back remains on the floor.","At the top of the movement, flex your abdominals and hold for a brief pause.","Then inhale and slowly lower yourself back down to the starting position."],muscleGroups:["core_abs"],equipment:["pilates_equipment"],level:"beginner",category:"strength",tags:["force:pull","mechanic:isolation"]},{id:"Wide-Grip_Rear_Pull-Up",name:"Wide-Grip Rear Pull-Up",instructions:["Grab the pull-up bar with the palms facing forward using a wide grip.","As you have both arms extended in front of you holding the bar, bring your torso forward and head so that there is an imaginary line from the pull-up bar to the back of your neck. This is your starting position.","Pull your torso up until the bar is near the back of your neck. To do this, draw the shoulders and upper arms down and back while slightly leaning your head forward. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.","After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.","Repeat this motion for the prescribed amount of repetitions."],muscleGroups:["back_posture"],equipment:[],level:"intermediate",category:"strength",tags:["force:pull","mechanic:compound","secondary:arms","secondary:back_posture","secondary:upper_body"]},{id:"Wind_Sprints",name:"Wind Sprints",instructions:["Hang from a pull-up bar using a pronated grip. Your arms and legs should be extended. This will be your starting position.","Begin by quickly raising one knee as high as you can. Do not swing your body or your legs. 3","Immediately reverse the motion, returning that leg to the starting position. Simultaneously raise the opposite knee as high as possible.","Continue alternating between legs until the set is complete."],muscleGroups:["core_abs"],equipment:[],level:"beginner",category:"strength",tags:["force:pull","mechanic:compound"]},{id:"Windmills",name:"Windmills",instructions:["Lie on your back with your arms extended out to the sides and your legs straight. This will be your starting position.","Lift one leg and quickly cross it over your body, attempting to touch the ground near the opposite hand.","Return to the starting position, and repeat with the opposite leg. Continue to alternate for 10-20 repetitions."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:pull","secondary:glutes","secondary:legs","secondary:back_posture"]},{id:"Worlds_Greatest_Stretch",name:"World's Greatest Stretch",instructions:["This is a three-part stretch. Begin by lunging forward, with your front foot flat on the ground and on the toes of your back foot. With your knees bent, squat down until your knee is almost touching the ground. Keep your torso erect, and hold this position for 10-20 seconds.","Now, place the arm on the same side as your front leg on the ground, with the elbow next to the foot. Your other hand should be placed on the ground, parallel to your lead leg, to help support you during this portion of the stretch.","After 10-20 seconds, place your hands on either side of your front foot. Raise the toes of the front foot off of the ground, and straighten your leg. You may need to reposition your rear leg to do so. Hold for 10-20 seconds, and then repeat the entire sequence for the other side."],muscleGroups:["legs"],equipment:[],level:"intermediate",category:"stretching",tags:["force:static","secondary:legs","secondary:glutes"]},{id:"Wrist_Circles",name:"Wrist Circles",instructions:["Start by standing straight with your feet being shoulder width apart from each other. Elevate your arms to the side of you until they are fully extended and parallel to the floor at a height that is evenly aligned with your shoulders. Tip: Your torso and arms should form the letter \"T: Your palms should be facing down. This is the starting position.","Keeping your entire body stationary except for the wrists, begin to rotate both wrists forward in a circular motion. Tip: Pretend that you are trying to draw circles by using your hands as the brush. Breathe normally as you perform this exercise.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:[],level:"beginner",category:"stretching",tags:["force:pull","mechanic:isolation"]},{id:"Zottman_Curl",name:"Zottman Curl",instructions:["Stand up with your torso upright and a dumbbell in each hand being held at arms length. The elbows should be close to the torso.","Make sure the palms of the hands are facing each other. This will be your starting position.","While holding the upper arm stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Your wrist should rotate so that you have a supinated (palms up) grip. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a second as you squeeze the biceps.","Now during the contracted position, rotate your wrist until you now have a pronated (palms facing down) grip with the thumb at a higher position than the pinky.","Slowly begin to bring the dumbbells back down using the pronated grip.","As the dumbbells close your thighs, start rotating the wrist so that you go back to a neutral (palms facing your body) grip.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]},{id:"Zottman_Preacher_Curl",name:"Zottman Preacher Curl",instructions:["Grab a dumbbell in each hand and place your upper arms on top of the preacher bench or the incline bench. The dumbbells should be held at shoulder height and the elbows should be flexed. Hold the dumbbells with the palms of your hands facing down. This will be your starting position.","As you breathe in, slowly lower the dumbbells keeping the palms down until your upper arm is extended and your biceps are fully stretched.","Now rotate your wrists once you are at the bottom of the movement so that the palms of the hands are facing up.","As you exhale, use your biceps to curl the weights up until they are fully contracted and the dumbbells are at shoulder height. Again, remember that to ensure full contraction you need to bring that small finger higher than the thumb.","Squeeze the biceps hard for a second at the contracted position and rotate your wrists so that the palms are facing down again.","Repeat for the recommended amount of repetitions."],muscleGroups:["arms"],equipment:["dumbbells"],level:"intermediate",category:"strength",tags:["force:pull","mechanic:isolation","secondary:arms"]}],l=new Map(s.map(e=>[e.id,e])),h=new Map(s.map(e=>[e.name.toLowerCase(),e]))},1319,[]);
